function secretManagementPackageSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["packageSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "@infisical/sdk", pattern: /@infisical\/sdk/i, evidence: "@infisical/sdk dependency evidence was detected." },
    { signal: "infisical", pattern: /"infisical"|\binfisical\b/i, evidence: "Infisical package or CLI evidence was detected." },
    { signal: "vault", pattern: /"vault"|\bvault\b/i, evidence: "Vault package or CLI evidence was detected." },
    { signal: "node-vault", pattern: /node-vault/i, evidence: "node-vault dependency evidence was detected." },
    { signal: "doppler", pattern: /"doppler"|\bdoppler\b/i, evidence: "Doppler package or CLI evidence was detected." },
    { signal: "sops", pattern: /"sops"|\bsops\b|\.sops/i, evidence: "SOPS package or config evidence was detected." },
    { signal: "sealed-secrets", pattern: /sealed-?secrets?|kubeseal|SealedSecret/i, evidence: "Sealed Secrets package or manifest evidence was detected." },
    { signal: "external-secrets", pattern: /external-?secrets?|ExternalSecret|SecretStore|ClusterSecretStore/i, evidence: "External Secrets package or manifest evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "package"));
}

function secretManagementSignalFromSpecs<T extends string>(
  sourceFiles: SecretManagementSourceFile[],
  spec: { signal: T; pattern: RegExp; evidence: string },
  label: string
): { signal: T; readiness: "ready" | "missing"; evidence: string; relatedHref: string } {
  const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
  return {
    signal: spec.signal,
    readiness: match ? "ready" : "missing",
    evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.signal} ${label} evidence was not detected.`,
    relatedHref: match?.sourceHref ?? "html/secret-management-readiness.html"
  };
}

async function buildContainerReadinessReport(walk: WalkResult): Promise<ContainerReadinessReport> {
  const sourceFiles = await containerSourceFiles(walk);
  const dockerfiles = containerDockerfiles(sourceFiles);
  const composeFiles = containerComposeFiles(sourceFiles);
  const configSignals = containerConfigSignals(sourceFiles);
  const instructionRisks = containerInstructionRisks(dockerfiles, configSignals);
  const labelPolicy = containerLabelPolicy(dockerfiles, configSignals, sourceFiles);
  const integrationSignals = containerIntegrationSignals(sourceFiles);
  const dockerfileRows = dockerfiles.map(({ text: _text, ...row }) => row);
  const hasDockerfile = dockerfiles.length > 0;
  const hasConfig = configSignals.some((item) => item.signal === "hadolint-config");
  const hasRegistryPolicy = configSignals.some((item) => item.signal === "trusted-registries");
  const hasLabelSchema = configSignals.some((item) => item.signal === "label-schema");
  const hasIntegration = integrationSignals.some((item) => ["pre-commit", "github-action", "gitlab-ci", "circleci", "jenkins"].includes(item.signal) && item.readiness === "ready");
  const hasMachineReport = integrationSignals.some((item) => ["sarif", "junit", "code-quality-report"].includes(item.signal) && item.readiness === "ready");
  const observedRisks = instructionRisks.filter((item) => item.readiness === "partial");

  const riskQueue: ContainerReadinessReport["riskQueue"] = [];
  if (!hasDockerfile) {
    riskQueue.push({
      priority: "medium",
      action: "Add a Dockerfile only if this project is meant to build container images.",
      why: "Container readiness is irrelevant for libraries without images, but runtime apps should make image build assumptions visible.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add .hadolint.yaml to document failure thresholds, ignored rules, registries, and label policy.",
      why: "Hadolint supports project-level config; undocumented CLI flags make Dockerfile quality gates hard to reproduce.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasIntegration) {
    riskQueue.push({
      priority: "high",
      action: "Run Hadolint in pre-commit or CI before container builds are published.",
      why: "Dockerfile linting is most useful before image build and release steps, not after a broken image reaches users.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasRegistryPolicy) {
    riskQueue.push({
      priority: "medium",
      action: "Declare trustedRegistries or a trusted registry CLI policy.",
      why: "Hadolint can warn when FROM images come from registries outside the allowed list.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasLabelSchema) {
    riskQueue.push({
      priority: "medium",
      action: "Define an image label schema for version, source, license, and documentation labels.",
      why: "Labels make built images traceable; Hadolint can enforce label formats such as semver, hash, url, email, and SPDX.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (observedRisks.length > 0) {
    riskQueue.push({
      priority: "medium",
      action: "Review observed Dockerfile risk patterns before building images.",
      why: `${observedRisks.length} Hadolint-style rule pattern(s) were detected in copied Dockerfile text.`,
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasMachineReport) {
    riskQueue.push({
      priority: "low",
      action: "Emit SARIF, JUnit, or code-quality output for Dockerfile lint findings.",
      why: "Machine-readable lint reports can be attached to CI artifacts and code scanning systems.",
      relatedHref: "html/container-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Hadolint against the original source tree before treating this report as lint approval.",
    why: "RepoTutor records static readiness patterns only; it does not parse the Dockerfile AST, execute ShellCheck, build images, or verify registry access.",
    relatedHref: "html/container-readiness.html"
  });

  return {
    summary: `Hadolint식 container readiness report: Dockerfile ${dockerfiles.length}개, Compose file ${composeFiles.length}개, config signal ${configSignals.length}개, instruction check ${instructionRisks.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Hadolint Dockerfile AST ShellCheck rules config ignored rules severity overrides trusted registries labels SARIF JUnit CI pre-commit",
    dockerfiles: dockerfileRows,
    composeFiles,
    configSignals,
    instructionRisks,
    labelPolicy,
    integrationSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "hadolint Dockerfile", purpose: "Lint the default Dockerfile with Hadolint best-practice and ShellCheck-backed rules." },
      { command: "hadolint --config .hadolint.yaml Dockerfile", purpose: "Run with project-specific ignored rules, severity overrides, trusted registries, and label schema." },
      { command: "hadolint --format sarif Dockerfile > hadolint.sarif", purpose: "Write SARIF output for code scanning or CI artifact review." },
      { command: "hadolint --failure-threshold warning Dockerfile", purpose: "Fail only when findings meet the configured minimum severity." },
      { command: "docker run --rm -i hadolint/hadolint < Dockerfile", purpose: "Run Hadolint via its container image without installing a local binary." }
    ],
    learnerNextSteps: [
      "Dockerfile이 없다면 이 프로젝트가 container image를 배포해야 하는지부터 확인하세요.",
      "FROM image tag, USER, package pinning, COPY/ADD, HEALTHCHECK, pipefail은 beginner가 image 품질을 이해하기 좋은 첫 점검 항목입니다.",
      ".hadolint.yaml의 ignored rule은 예외 사유가 좁고 문서화되어 있는지 확인하세요.",
      "RepoTutor는 Docker build나 registry 검증을 하지 않으므로 실제 배포 전 원본 repo에서 Hadolint를 실행하세요."
    ]
  };
}

type ContainerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

type ContainerDockerfile = ContainerReadinessReport["dockerfiles"][number] & {
  text: string;
};

async function containerSourceFiles(walk: WalkResult): Promise<ContainerSourceFile[]> {
  const files: ContainerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !containerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 240_000);
    if (!text) continue;
    if (!containerPathSignal(file.relPath) && !containerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function containerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(Dockerfile|Containerfile|docker-compose\.ya?ml|compose\.ya?ml|\.hadolint\.ya?ml|hadolint\.ya?ml|\.pre-commit-config\.ya?ml|README\.md|SECURITY\.md)$/i.test(base)
    || /\.dockerfile$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /\.(ya?ml|json|md|sh)$/i.test(filePath);
}

function containerPathSignal(filePath: string): boolean {
  return /(Dockerfile|Containerfile|docker-compose|compose\.ya?ml|hadolint|container|image|pre-commit|workflow|gitlab-ci|circleci|jenkins)/i.test(filePath);
}

function containerContentSignal(text: string): boolean {
  return /\b(FROM|RUN|COPY|ADD|USER|HEALTHCHECK|ENTRYPOINT|CMD|LABEL)\b|hadolint|Dockerfile|trustedRegistries|failure-threshold|label-schema|strict-labels|disable-ignore-pragma|gitlab_codeclimate|sarif|junit/i.test(text);
}

function containerDockerfiles(sourceFiles: ContainerSourceFile[]): ContainerDockerfile[] {
  return sourceFiles
    .filter((source) => /(^|\/)(Dockerfile|Containerfile)(\.[^/]*)?$|\.dockerfile$/i.test(source.filePath))
    .map((source) => {
      const baseImages = [...source.text.matchAll(/^FROM\s+(?:--platform=\S+\s+)?([^\s#]+)(?:\s+AS\s+\S+)?/gim)].map((match) => match[1] ?? "").filter(Boolean);
      const instructionKinds = [...new Set([...source.text.matchAll(/^\s*([A-Z][A-Z0-9_-]+)\b/gm)].map((match) => match[1] ?? "").filter(Boolean))];
      return {
        filePath: source.filePath,
        stageCount: baseImages.length,
        baseImages,
        instructionKinds,
        readiness: baseImages.length > 0 ? "ready" : "partial",
        evidence: baseImages.length > 0 ? `${source.filePath} defines ${baseImages.length} FROM stage(s).` : `${source.filePath} is Dockerfile-like but no FROM instruction was detected.`,
        sourceHref: source.sourceHref,
        text: source.text
      };
    });
}

function containerComposeFiles(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["composeFiles"] {
  return sourceFiles
    .filter((source) => /(^|\/)(docker-compose|compose)\.ya?ml$/i.test(source.filePath))
    .map((source) => {
      const servicesBlock = source.text.match(/(?:^|\n)services:\s*\n([\s\S]*?)(?:\n\S|\s*$)/i)?.[1] ?? "";
      const serviceCount = [...servicesBlock.matchAll(/^\s{2,}([A-Za-z0-9_.-]+):\s*(?:#.*)?$/gm)].length;
      return {
        filePath: source.filePath,
        serviceCount,
        readiness: serviceCount > 0 ? "ready" : "partial",
        evidence: serviceCount > 0 ? `${source.filePath} declares ${serviceCount} Compose service(s).` : `${source.filePath} is compose-like but service count could not be inferred statically.`,
        sourceHref: source.sourceHref
      };
    });
}

function containerConfigSignals(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["configSignals"] {
  const rows: ContainerReadinessReport["configSignals"] = [];
  for (const source of sourceFiles) {
    for (const signal of containerConfigSignalTypes(source.filePath, source.text)) {
      rows.push({
        filePath: source.filePath,
        signal,
        readiness: signal === "unknown" ? "partial" : "ready",
        evidence: containerConfigEvidence(source.filePath, signal),
        sourceHref: source.sourceHref
      });
    }
  }
  return rows.slice(0, 140);
}

function containerConfigSignalTypes(filePath: string, text: string): ContainerReadinessReport["configSignals"][number]["signal"][] {
  const signals = new Set<ContainerReadinessReport["configSignals"][number]["signal"]>();
  if (/\.hadolint\.ya?ml$|hadolint\.ya?ml$/i.test(filePath) || /hadolint\s+--config|HADOLINT_/i.test(text)) signals.add("hadolint-config");
  if (/ignored:\s*\[|ignored:\s*\n|--ignore\s+DL|HADOLINT_IGNORE|#\s*hadolint\s+(global\s+)?ignore=/i.test(text)) signals.add("ignored-rules");
  if (/override:\s*\n|--(error|warning|info|style)\s+DL|HADOLINT_OVERRIDE_/i.test(text)) signals.add("severity-override");
  if (/failure-threshold|HADOLINT_FAILURE_THRESHOLD/i.test(text)) signals.add("failure-threshold");
  if (/trustedRegistries|trusted-registry|HADOLINT_TRUSTED_REGISTRIES/i.test(text)) signals.add("trusted-registries");
  if (/label-schema|require-label|HADOLINT_REQUIRE_LABELS/i.test(text)) signals.add("label-schema");
  if (/strict-labels|HADOLINT_STRICT_LABELS/i.test(text)) signals.add("strict-labels");
  if (/disable-ignore-pragma|HADOLINT_DISABLE_IGNORE_PRAGMA/i.test(text)) signals.add("disable-ignore-pragma");
  if (/--format\s+(json|checkstyle|codeclimate|gitlab_codeclimate|gnu|codacy|sonarqube|sarif|junit)|HADOLINT_FORMAT|format:\s*(json|sarif|junit|codeclimate|gitlab_codeclimate)/i.test(text)) signals.add("output-format");
  if (signals.size === 0 && /hadolint/i.test(text)) signals.add("unknown");
  return [...signals];
}

function containerConfigEvidence(filePath: string, signal: ContainerReadinessReport["configSignals"][number]["signal"]): string {
  if (signal === "hadolint-config") return `${filePath} provides or references Hadolint configuration.`;
  if (signal === "ignored-rules") return `${filePath} references Hadolint ignored rules or inline/global ignores.`;
  if (signal === "severity-override") return `${filePath} references Hadolint severity overrides.`;
  if (signal === "failure-threshold") return `${filePath} references failure threshold behavior.`;
  if (signal === "trusted-registries") return `${filePath} references trusted registry policy.`;
  if (signal === "label-schema") return `${filePath} references image label schema policy.`;
  if (signal === "strict-labels") return `${filePath} references strict label enforcement.`;
  if (signal === "disable-ignore-pragma") return `${filePath} disables inline ignore pragmas.`;
  if (signal === "output-format") return `${filePath} references machine-readable Hadolint output format.`;
  return `${filePath} contains Hadolint-related configuration evidence.`;
}

function containerInstructionRisks(dockerfiles: ContainerDockerfile[], configSignals: ContainerReadinessReport["configSignals"]): ContainerReadinessReport["instructionRisks"] {
  const allText = dockerfiles.map((item) => item.text).join("\n");
  const allDockerfiles = dockerfiles.map((item) => item.filePath).join(", ") || "Dockerfile";
  const hasDockerfile = dockerfiles.length > 0;
  const hasTrustedRegistry = configSignals.some((item) => item.signal === "trusted-registries");
  const specs: Array<{ rule: ContainerReadinessReport["instructionRisks"][number]["rule"]; severity: ContainerReadinessReport["instructionRisks"][number]["severity"]; pattern: RegExp; missingEvidence: string; hitEvidence: string }> = [
    { rule: "DL3002", severity: "warning", pattern: /(^|\n)\s*USER\s+root\b/i, missingEvidence: "No explicit USER root instruction was detected.", hitEvidence: "USER root pattern was detected." },
    { rule: "DL3006", severity: "warning", pattern: /^FROM\s+(?:--platform=\S+\s+)?(?:[^\s:@]+\/)?[^\s:@]+(?:\s|$)/gim, missingEvidence: "All detected FROM images appear to include a tag, digest, or alias-only reference.", hitEvidence: "FROM image without explicit tag or digest may be present." },
    { rule: "DL3007", severity: "warning", pattern: /^FROM\s+.*:latest\b/gim, missingEvidence: "No FROM latest tag was detected.", hitEvidence: "FROM latest tag was detected." },
    { rule: "DL3008", severity: "warning", pattern: /RUN\s+.*apt-get\s+.*install(?![^&;\n]*=)[^|\n]*/i, missingEvidence: "No obvious unpinned apt-get install pattern was detected.", hitEvidence: "apt-get install without visible version pin may be present." },
    { rule: "DL3013", severity: "warning", pattern: /RUN\s+.*(?:pip|pip3|python\s+-m\s+pip)\s+install(?![^&;\n]*(==|~=|>=|<=|!=|<|>|-r|--requirement|\.[\s;&|]|\.whl|\.tar\.gz))[^|\n]*/i, missingEvidence: "No obvious unpinned pip install pattern was detected.", hitEvidence: "pip install without visible version pin or requirements file may be present." },
    { rule: "DL3016", severity: "warning", pattern: /RUN\s+.*npm\s+install\s+(?!(-g\s+)?[^&;\n]*@)[A-Za-z0-9@/_-]+/i, missingEvidence: "No obvious unpinned npm install pattern was detected.", hitEvidence: "npm install without visible version pin may be present." },
    { rule: "DL3018", severity: "warning", pattern: /RUN\s+.*apk\s+add(?![^&;\n]*=)[^|\n]*/i, missingEvidence: "No obvious unpinned apk add pattern was detected.", hitEvidence: "apk add without visible version pin may be present." },
    { rule: "DL3020", severity: "error", pattern: /^ADD\s+(?!.*\.(tar|tgz|tar\.gz|zip)\b)/gim, missingEvidence: "No ADD-for-plain-copy pattern was detected.", hitEvidence: "ADD is used where COPY may be clearer." },
    { rule: "DL3025", severity: "warning", pattern: /^(CMD|ENTRYPOINT)\s+(?!\[)/gim, missingEvidence: "CMD/ENTRYPOINT instructions appear to use JSON notation when present.", hitEvidence: "Shell-form CMD or ENTRYPOINT was detected." },
    { rule: "DL3026", severity: "error", pattern: /^FROM\s+(?!scratch\b|[A-Za-z0-9_.-]+(?:\s+AS\s+\S+)?$)/gim, missingEvidence: hasTrustedRegistry ? "Trusted registry policy is configured." : "No trusted registry policy was found for FROM image validation.", hitEvidence: "FROM image registry should be checked against trustedRegistries." },
    { rule: "DL3042", severity: "warning", pattern: /RUN\s+.*(?:pip|pip3|python\s+-m\s+pip)\s+install(?![^&;\n]*--no-cache-dir)/i, missingEvidence: "No pip install without --no-cache-dir was detected.", hitEvidence: "pip install without --no-cache-dir may cache packages in the image layer." },
    { rule: "DL3057", severity: "info", pattern: /^HEALTHCHECK\b/gim, missingEvidence: "HEALTHCHECK was not detected.", hitEvidence: "HEALTHCHECK instruction was detected." },
    { rule: "DL3059", severity: "info", pattern: /^RUN\b[\s\S]*\n\s*RUN\b/i, missingEvidence: "Multiple consecutive RUN instructions were not detected.", hitEvidence: "Multiple consecutive RUN instructions may be present." },
    { rule: "DL4006", severity: "warning", pattern: /^RUN\s+.*\|.*$/gim, missingEvidence: "RUN pipelines were not detected.", hitEvidence: "RUN pipeline detected; SHELL pipefail should be reviewed." },
    { rule: "SC", severity: "external", pattern: /^RUN\s+.*(\$\(|`|&&|\|\||;)/gim, missingEvidence: "No complex shell RUN instruction was detected.", hitEvidence: "Complex RUN shell text exists; Hadolint delegates Bash checks to ShellCheck." }
  ];

  return specs.map((spec) => {
    const matched = hasDockerfile && spec.pattern.test(allText);
    spec.pattern.lastIndex = 0;
    const readiness = !hasDockerfile ? "missing" : matched ? "partial" : spec.rule === "DL3026" && !hasTrustedRegistry ? "external" : spec.rule === "DL3057" && !matched ? "external" : "ready";
    return {
      rule: spec.rule,
      severity: spec.severity,
      readiness,
      evidence: !hasDockerfile ? "No Dockerfile target was detected." : matched ? `${allDockerfiles}: ${spec.hitEvidence}` : spec.missingEvidence,
      relatedHref: matched ? dockerfiles[0]?.sourceHref ?? "html/container-readiness.html" : "html/container-readiness.html"
    };
  });
}

function containerLabelPolicy(dockerfiles: ContainerDockerfile[], configSignals: ContainerReadinessReport["configSignals"], sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["labelPolicy"] {
  const allText = dockerfiles.map((item) => item.text).join("\n");
  const labelSchemaFiles = configSignals.filter((item) => item.signal === "label-schema");
  const labelSchemaSources = sourceFiles.filter((source) => labelSchemaFiles.some((item) => item.filePath === source.filePath));
  const hasDockerfile = dockerfiles.length > 0;
  const labels: ContainerReadinessReport["labelPolicy"][number]["label"][] = ["author", "contact", "created", "version", "documentation", "git-revision", "license"];
  return labels.map((label) => {
    const labelPattern = new RegExp(`(?:LABEL\\s+[^\\n]*\\b${label}\\b|label-schema:[\\s\\S]*\\b${label}\\b|${label}:\\s*(?:text|email|rfc3339|semver|url|hash|spdx))`, "i");
    const matchedDockerfile = labelPattern.test(allText);
    const matchedConfig = labelSchemaSources.find((source) => labelPattern.test(source.text));
    return {
      label,
      readiness: matchedDockerfile || matchedConfig ? "ready" : hasDockerfile ? "external" : "missing",
      evidence: matchedDockerfile ? `Dockerfile LABEL or schema evidence includes ${label}.` : matchedConfig ? `Hadolint label-schema config should be checked for ${label}.` : `${label} image label policy was not detected.`,
      relatedHref: matchedDockerfile ? dockerfiles[0]?.sourceHref ?? "html/container-readiness.html" : matchedConfig?.sourceHref ?? "html/container-readiness.html"
    };
  });
}

function containerIntegrationSignals(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["integrationSignals"] {
  const specs: Array<{ signal: ContainerReadinessReport["integrationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "pre-commit", pattern: /pre-commit|hadolint-docker|types:\s*\["?dockerfile/i, evidence: "pre-commit Hadolint hook evidence was detected." },
    { signal: "github-action", pattern: /hadolint-action|uses:\s*hadolint|hadolint\/hadolint-action/i, evidence: "GitHub Actions Hadolint evidence was detected." },
    { signal: "gitlab-ci", pattern: /gitlab_codeclimate|\.gitlab-ci|reports:\s*codequality/i, evidence: "GitLab code quality integration evidence was detected." },
    { signal: "circleci", pattern: /circleci|docker\/hadolint|ignore-rules|trusted-registries/i, evidence: "CircleCI Hadolint integration evidence was detected." },
    { signal: "jenkins", pattern: /Jenkinsfile|jenkins|archiveArtifacts|recordIssues/i, evidence: "Jenkins Hadolint integration evidence was detected." },
    { signal: "editor", pattern: /vscode-hadolint|Hadolint extension|editor integration/i, evidence: "editor integration evidence was detected." },
    { signal: "code-quality-report", pattern: /gitlab_codeclimate|codeclimate|sonarqube|codacy|checkstyle/i, evidence: "code quality report format evidence was detected." },
    { signal: "sarif", pattern: /--format\s+sarif|format:\s*sarif|HADOLINT_FORMAT=sarif/i, evidence: "SARIF report evidence was detected." },
    { signal: "junit", pattern: /--format\s+junit|format:\s*junit|HADOLINT_FORMAT=junit/i, evidence: "JUnit report evidence was detected." }
  ];
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.signal} integration evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/container-readiness.html"
    };
  });
}

async function buildCodeQualityReport(walk: WalkResult): Promise<CodeQualityReport> {
  const sourceFiles = await codeQualitySourceFiles(walk);
  const toolConfigs = codeQualityToolConfigs(sourceFiles);
  const formatterSignals = codeQualityFormatterSignals(sourceFiles);
  const linterSignals = codeQualityLinterSignals(sourceFiles);
  const assistSignals = codeQualityAssistSignals(sourceFiles);
  const ciSignals = codeQualityCiSignals(sourceFiles);
  const languageCoverage = codeQualityLanguageCoverage(walk, toolConfigs);
  const hasWebFiles = languageCoverage.some((item) => item.fileCount > 0 && item.language !== "unknown");
  const hasBiomeConfig = toolConfigs.some((item) => item.tool === "biome-config");
  const hasFormatter = formatterSignals.some((item) => ["formatter-enabled", "format-command"].includes(item.signal) && item.readiness === "ready");
  const hasLinter = linterSignals.some((item) => ["linter-enabled", "rule-groups", "recommended-rules"].includes(item.signal) && item.readiness === "ready");
  const hasAssist = assistSignals.some((item) => ["assist-enabled", "organize-imports"].includes(item.signal) && item.readiness === "ready");
  const hasCi = ciSignals.some((item) => ["biome-ci", "biome-check", "github-action", "gitlab-ci", "pre-commit"].includes(item.signal) && item.readiness === "ready");
  const hasReporter = ciSignals.some((item) => item.signal === "reporter" && item.readiness === "ready");

  const riskQueue: CodeQualityReport["riskQueue"] = [];
  if (hasWebFiles && !hasBiomeConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a biome.json or biome.jsonc config when this repo wants unified formatting and linting.",
      why: "Biome works with sane defaults, but a committed config makes formatter, linter, assist, file include, and VCS ignore behavior reproducible.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasFormatter) {
    riskQueue.push({
      priority: "high",
      action: "Add a formatter command such as biome format or biome check.",
      why: "Biome's formatter is a first-class quality gate for JavaScript, TypeScript, JSX, JSON, CSS, and GraphQL files.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasLinter) {
    riskQueue.push({
      priority: "high",
      action: "Add a linter command or enable linter rules in config.",
      why: "Biome lint diagnostics and safe fixes give learners a concrete path from source findings to code health improvements.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasAssist) {
    riskQueue.push({
      priority: "medium",
      action: "Consider enabling assist actions such as organizeImports.",
      why: "Biome can centralize import organization and source actions that otherwise drift between editor settings and ad hoc scripts.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasCi) {
    riskQueue.push({
      priority: "medium",
      action: "Run biome ci or biome check in CI before publishing generated learning artifacts.",
      why: "Local formatting and linting are useful, but CI makes the code-quality contract visible to every contributor.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasReporter) {
    riskQueue.push({
      priority: "low",
      action: "Choose a machine-readable or CI-friendly reporter when findings need review artifacts.",
      why: "Biome supports diagnostics/reporting workflows; RepoTutor should surface whether a repo has a durable quality report path.",
      relatedHref: "html/code-quality.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Biome against the original source tree before treating this report as quality approval.",
    why: "RepoTutor records static code-quality readiness only; it does not execute Biome, ESLint, Prettier, editor LSPs, or unsafe fixes.",
    relatedHref: "html/code-quality.html"
  });

  return {
    summary: `Biome식 code quality report: config ${toolConfigs.length}개, formatter signal ${formatterSignals.length}개, linter signal ${linterSignals.length}개, CI/editor signal ${ciSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Biome formatter linter check ci biome.json assist organize imports diagnostics reporter editor LSP VCS ignore safe fixes",
    toolConfigs,
    formatterSignals,
    linterSignals,
    assistSignals,
    ciSignals,
    languageCoverage,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx @biomejs/biome check .", purpose: "Run formatter, linter, assist, and other enabled checks without writing changes." },
      { command: "npx @biomejs/biome check --write .", purpose: "Apply safe formatting, lint, and assist fixes where the project policy allows writes." },
      { command: "npx @biomejs/biome ci .", purpose: "Run the CI-oriented quality gate for all configured files." },
      { command: "npx @biomejs/biome format --write .", purpose: "Format supported web-language files." },
      { command: "npx @biomejs/biome lint --write .", purpose: "Run lint rules and apply safe fixes." }
    ],
    learnerNextSteps: [
      "package.json scripts, biome.json, editor settings, and CI workflows should agree on the same quality gate.",
      "Formatter readiness answers style drift; linter readiness answers code-health diagnostics; assist readiness answers import/source-action drift.",
      "If the repo already uses ESLint or Prettier, decide whether Biome complements, replaces, or intentionally stays out of that scope.",
      "RepoTutor does not run Biome, so use the recommended commands on the original source tree before claiming code-quality pass/fail."
    ]
  };
}

type CodeQualitySourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function codeQualitySourceFiles(walk: WalkResult): Promise<CodeQualitySourceFile[]> {
  const files: CodeQualitySourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !codeQualityInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!codeQualityPathSignal(file.relPath) && !codeQualityContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function codeQualityInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|biome\.jsonc?|\.biome\.jsonc?|\.editorconfig|\.prettierrc(\..*)?|prettier\.config\.[cm]?[jt]s|eslint\.config\.[cm]?[jt]s|\.eslintrc(\..*)?|\.pre-commit-config\.ya?ml)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /^\.vscode\/settings\.json$/i.test(filePath)
    || /^\.gitlab-ci\.ya?ml$/i.test(filePath)
    || /\.(json|jsonc|ya?ml|toml|md|[cm]?[jt]s)$/i.test(filePath);
}

function codeQualityPathSignal(filePath: string): boolean {
  return /(biome|eslint|prettier|lint|format|pre-commit|workflow|gitlab-ci|\.vscode|editorconfig)/i.test(filePath);
}

function codeQualityContentSignal(text: string): boolean {
  return /@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b|biome\.json|organizeImports|assist|formatter|linter|prettier|eslint|reporter|diagnostic|safe fix|unsafe/i.test(text);
}

function codeQualityToolConfigs(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["toolConfigs"] {
  const rows: CodeQualityReport["toolConfigs"] = [];
  for (const source of sourceFiles) {
    const base = path.basename(source.filePath).toLowerCase();
    const push = (tool: CodeQualityReport["toolConfigs"][number]["tool"], readiness: CodeQualityReport["toolConfigs"][number]["readiness"], evidence: string) => {
      rows.push({ filePath: source.filePath, tool, readiness, evidence, sourceHref: source.sourceHref });
    };
    if (/^\.?biome\.jsonc?$/.test(base)) push("biome-config", "ready", `${source.filePath} is a Biome project configuration file.`);
    if (/^package\.json$/.test(base) && /@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b/i.test(source.text)) push("package-script", "ready", `${source.filePath} references Biome dependency or commands.`);
    if (/^package\.json$/.test(base) && /\b(eslint|prettier)\b/i.test(source.text) && !/@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b/i.test(source.text)) push("package-script", "partial", `${source.filePath} references ESLint or Prettier scripts without Biome.`);
    if (/^(eslint\.config\.[cm]?[jt]s|\.eslintrc(\..*)?)$/i.test(base)) push("eslint-config", "partial", `${source.filePath} is an ESLint configuration file.`);
    if (/^(\.prettierrc(\..*)?|prettier\.config\.[cm]?[jt]s)$/i.test(base)) push("prettier-config", "partial", `${source.filePath} is a Prettier configuration file.`);
    if (/^(\.editorconfig|settings\.json)$/i.test(base) && /(format|biome|prettier|eslint|editor\.defaultFormatter)/i.test(source.text)) push("editor-config", "partial", `${source.filePath} contains editor formatting or linting configuration.`);
    if (rows.length < 140 && /biome/i.test(source.text) && !rows.some((item) => item.filePath === source.filePath)) push("unknown", "partial", `${source.filePath} contains Biome-related text.`);
  }
  return rows.slice(0, 140);
}

function codeQualityFormatterSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["formatterSignals"] {
  const specs: Array<{ signal: CodeQualityReport["formatterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "formatter-enabled", pattern: /"formatter"\s*:|formatter:\s|formatter\s+enabled|biome\s+format/i, evidence: "formatter configuration or command evidence was detected." },
    { signal: "format-command", pattern: /\bbiome\s+format\b|@biomejs\/biome\s+format|"(format|fmt)"\s*:\s*"[^"]*(biome|prettier)/i, evidence: "format command evidence was detected." },
    { signal: "write-mode", pattern: /--write|--fix|check\s+--write|lint\s+--write|format\s+--write/i, evidence: "write/fix mode evidence was detected." },
    { signal: "language-support", pattern: /JavaScript|TypeScript|JSX|JSON|CSS|GraphQL|javascript|typescript|json|css|graphql/i, evidence: "supported language coverage evidence was detected." },
    { signal: "line-width", pattern: /lineWidth|printWidth|max_line_length/i, evidence: "line width formatting policy evidence was detected." },
    { signal: "indent-style", pattern: /indentStyle|indent_size|indent_style|tabWidth/i, evidence: "indent formatting policy evidence was detected." },
    { signal: "prettier-compat", pattern: /prettier|Prettier/i, evidence: "Prettier compatibility or coexistence evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "formatter");
}

function codeQualityLinterSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["linterSignals"] {
  const specs: Array<{ signal: CodeQualityReport["linterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "linter-enabled", pattern: /"linter"\s*:|linter:\s|biome\s+lint|biome\s+check/i, evidence: "linter configuration or command evidence was detected." },
    { signal: "rule-groups", pattern: /"rules"\s*:|"style"\s*:|"correctness"\s*:|"suspicious"\s*:|"nursery"\s*:|"complexity"\s*:/i, evidence: "Biome-style rule group evidence was detected." },
    { signal: "custom-rules", pattern: /plugins?|\.grit|rules\s*:/i, evidence: "custom rule or plugin evidence was detected." },
    { signal: "recommended-rules", pattern: /recommended\s*:\s*(true|\"on\")|recommended/i, evidence: "recommended rule mode evidence was detected." },
    { signal: "safe-fixes", pattern: /safe fix|safe fixes|lint\s+--write|check\s+--write/i, evidence: "safe fix workflow evidence was detected." },
    { signal: "unsafe-fixes", pattern: /--unsafe|unsafe/i, evidence: "unsafe fix workflow evidence was detected." },
    { signal: "dependency-rule", pattern: /noUndeclaredDependencies|no-undeclared-dependencies/i, evidence: "dependency declaration lint evidence was detected." },
    { signal: "import-cycle-rule", pattern: /noImportCycles|import cycle|no-import-cycles/i, evidence: "import cycle lint evidence was detected." },
    { signal: "promise-rule", pattern: /noFloatingPromises|floating promises|no-floating-promises/i, evidence: "promise lint evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "linter");
}

function codeQualityAssistSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["assistSignals"] {
  const specs: Array<{ signal: CodeQualityReport["assistSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "assist-enabled", pattern: /"assist"\s*:|assist:\s|source action|sourceAction/i, evidence: "assist/source-action configuration evidence was detected." },
    { signal: "organize-imports", pattern: /organizeImports|organize imports|source\.organizeImports/i, evidence: "organize imports evidence was detected." },
    { signal: "sorted-keys", pattern: /useSortedKeys|sorted keys|sort(ed)? keys/i, evidence: "sorted key assist evidence was detected." },
    { signal: "plugins", pattern: /"plugins"\s*:|\.grit|plugin/i, evidence: "Biome plugin evidence was detected." },
    { signal: "vcs-ignore", pattern: /"vcs"\s*:|useIgnoreFile|clientKind|\.gitignore/i, evidence: "VCS ignore integration evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "assist");
}

function codeQualityCiSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["ciSignals"] {
  const specs: Array<{ signal: CodeQualityReport["ciSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "biome-ci", pattern: /\bbiome\s+ci\b|@biomejs\/biome\s+ci/i, evidence: "biome ci evidence was detected." },
    { signal: "biome-check", pattern: /\bbiome\s+check\b|@biomejs\/biome\s+check/i, evidence: "biome check evidence was detected." },
    { signal: "github-action", pattern: /\.github\/workflows|github actions|actions\/checkout|setup-node|biomejs\/setup-biome/i, evidence: "GitHub Actions quality gate evidence was detected." },
    { signal: "gitlab-ci", pattern: /\.gitlab-ci|gitlab/i, evidence: "GitLab CI quality gate evidence was detected." },
    { signal: "pre-commit", pattern: /pre-commit|repos:\s*\n|biome.*pre-commit/i, evidence: "pre-commit quality gate evidence was detected." },
    { signal: "package-script", pattern: /"(lint|format|fmt|check|ci)"\s*:\s*"[^"]*(biome|eslint|prettier)/i, evidence: "package script quality gate evidence was detected." },
    { signal: "editor-lsp", pattern: /biomejs\.biome|language server|LSP|editor\.defaultFormatter|\.vscode/i, evidence: "editor or LSP integration evidence was detected." },
    { signal: "reporter", pattern: /--reporter|reporter|diagnostic|junit|github|json|summary/i, evidence: "reporter or diagnostic output evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "CI/editor");
}

function codeQualitySignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: CodeQualitySourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    spec.pattern.lastIndex = 0;
    return {
      signal: spec.signal,
      readiness: match ? "ready" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/code-quality.html"
    };
  });
}

function codeQualityLanguageCoverage(walk: WalkResult, toolConfigs: CodeQualityReport["toolConfigs"]): CodeQualityReport["languageCoverage"] {
  const hasQualityTool = toolConfigs.some((item) => ["biome-config", "package-script", "eslint-config", "prettier-config"].includes(item.tool));
  const specs: Array<{ language: CodeQualityReport["languageCoverage"][number]["language"]; pattern: RegExp }> = [
    { language: "javascript", pattern: /\.(mjs|cjs|js)$/i },
    { language: "typescript", pattern: /\.ts$/i },
    { language: "jsx", pattern: /\.(jsx|tsx)$/i },
    { language: "json", pattern: /\.jsonc?$/i },
    { language: "css", pattern: /\.css$/i },
    { language: "graphql", pattern: /\.(graphql|gql)$/i },
    { language: "html", pattern: /\.html$/i },
    { language: "markdown", pattern: /\.mdx?$/i }
  ];
  return specs.map((spec) => {
    const count = walk.files.filter((file) => spec.pattern.test(file.relPath)).length;
    const readiness = count === 0 ? "missing" : hasQualityTool ? "ready" : "external";
    return {
      language: spec.language,
      fileCount: count,
      readiness,
      evidence: count === 0 ? `${spec.language} files were not detected.` : hasQualityTool ? `${count} ${spec.language} file(s) can be reviewed against detected quality tooling.` : `${count} ${spec.language} file(s) exist but no code-quality tool config was detected.`,
      relatedHref: "html/code-quality.html"
    };
  });
}

async function buildDocumentationReport(walk: WalkResult): Promise<DocumentationReport> {
  const sourceFiles = await documentationSourceFiles(walk);
  const siteConfigs = documentationSiteConfigs(sourceFiles);
  const contentSurfaces = documentationContentSurfaces(walk, siteConfigs);
  const navigationSignals = documentationNavigationSignals(sourceFiles);
  const qualitySignals = documentationQualitySignals(sourceFiles);
  const localizationSignals = documentationLocalizationSignals(sourceFiles);
  const releaseSignals = documentationReleaseSignals(sourceFiles);
  const hasDocContent = contentSurfaces.some((item) => item.count > 0 && ["docs", "blog", "pages", "mdx", "versioned-docs"].includes(item.surface));
  const hasDocusaurusConfig = siteConfigs.some((item) => item.configType === "docusaurus-config");
  const hasNavigation = navigationSignals.some((item) => ["sidebar", "navbar", "footer"].includes(item.signal) && item.readiness === "ready");
  const hasBuild = releaseSignals.some((item) => item.signal === "build-script" && item.readiness === "ready");
  const hasDeploy = releaseSignals.some((item) => ["deploy-script", "github-pages", "netlify", "vercel", "ci-preview"].includes(item.signal) && item.readiness === "ready");
  const hasSearch = qualitySignals.some((item) => item.signal === "search" && item.readiness === "ready");
  const hasSeo = qualitySignals.some((item) => ["seo", "sitemap"].includes(item.signal) && item.readiness === "ready");
  const hasLocalization = localizationSignals.some((item) => item.readiness === "ready");
  const hasVersioning = contentSurfaces.some((item) => item.surface === "versioned-docs" && item.count > 0);

  const riskQueue: DocumentationReport["riskQueue"] = [];
  if (hasDocContent && !hasDocusaurusConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add or identify docusaurus.config when this repository is meant to publish a documentation website.",
      why: "Docusaurus keeps docs, blog, pages, navbar, footer, i18n, and plugin behavior reproducible through a committed site config.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasNavigation) {
    riskQueue.push({
      priority: "medium",
      action: "Define sidebar, navbar, or footer navigation for the main documentation paths.",
      why: "Docusaurus documentation is easier to learn when source folders map to visible navigation instead of isolated markdown files.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasBuild) {
    riskQueue.push({
      priority: "high",
      action: "Add a documented build command such as docusaurus build or an equivalent docs build script.",
      why: "A static documentation report cannot prove the site compiles; learners need a repeatable command for broken links, MDX, and generated routes.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasDeploy) {
    riskQueue.push({
      priority: "medium",
      action: "Record how the documentation site is previewed or deployed.",
      why: "Docusaurus sites often rely on GitHub Pages, Netlify, Vercel, or CI previews, and that path should be visible before publication.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasSearch) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether the docs need search and record the chosen search integration.",
      why: "Public documentation sites usually need a durable search path such as Algolia or local search as content grows.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasSeo) {
    riskQueue.push({
      priority: "low",
      action: "Check sitemap and SEO metadata before treating the docs site as publication-ready.",
      why: "A docs site can render locally while still being hard to discover or inspect in search/social previews.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasLocalization) {
    riskQueue.push({
      priority: "low",
      action: "Mark i18n as intentionally out of scope or add locale configuration when the docs serve multiple languages.",
      why: "Docusaurus has first-class i18n surfaces; RepoTutor should show whether localization is absent by design or simply missing.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasVersioning) {
    riskQueue.push({
      priority: "low",
      action: "Decide whether versioned docs are needed for released APIs or product versions.",
      why: "Docusaurus docs versioning is important when learners must match documentation to a specific release line.",
      relatedHref: "html/documentation.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Docusaurus against the original source tree before treating this report as documentation approval.",
    why: "RepoTutor records static documentation readiness only; it does not run MDX compilation, route generation, link checking, search indexing, or deployment.",
    relatedHref: "html/documentation.html"
  });

  return {
    summary: `Docusaurus식 documentation report: site config ${siteConfigs.length}개, content surface ${contentSurfaces.length}개, navigation signal ${navigationSignals.length}개, release signal ${releaseSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Docusaurus docs blog pages sidebars docusaurus.config themeConfig navbar footer i18n versioning search build deploy",
    siteConfigs,
    contentSurfaces,
    navigationSignals,
    qualitySignals,
    localizationSignals,
    releaseSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npm run build", purpose: "Build the documentation site and catch MDX, routing, and broken-link failures through the project script." },
      { command: "npm run serve", purpose: "Serve the built documentation locally before sharing the output." },
      { command: "npm run docusaurus docs:version 1.0", purpose: "Create a versioned docs snapshot when the project publishes version-specific documentation." },
      { command: "npm run start -- --locale fr", purpose: "Preview a localized documentation build when i18n is enabled." },
      { command: "npx docusaurus build", purpose: "Run the Docusaurus build directly when no package script wraps it yet." }
    ],
    learnerNextSteps: [
      "Check whether docs, blog, and custom pages are visible through sidebars, navbar, or footer navigation.",
      "Use build and serve commands on the original source tree before claiming documentation pass/fail status.",
      "If the repo uses another docs stack, treat Docusaurus signals as a comparison checklist rather than a required dependency.",
      "Record why i18n, versioning, search, or deploy previews are intentionally omitted when they are out of scope."
    ]
  };
}

type DocumentationSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function documentationSourceFiles(walk: WalkResult): Promise<DocumentationSourceFile[]> {
  const files: DocumentationSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !documentationInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!documentationPathSignal(file.relPath) && !documentationContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function documentationInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|docusaurus\.config\.[cm]?[jt]s|sidebars\.[cm]?[jt]s|sidebars\.json|README\.md|crowdin\.ya?ml|netlify\.toml|vercel\.json)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(^|\/)(docs|blog|src\/pages|pages|static|public|i18n|versioned_docs|versioned_sidebars)\//i.test(filePath)
    || /\.(mdx?|[cm]?[jt]sx?|json|ya?ml|toml)$/i.test(filePath);
}

function documentationPathSignal(filePath: string): boolean {
  return /(docusaurus|sidebars?|docs\/|blog\/|src\/pages|\/pages\/|i18n\/|versioned_docs|versioned_sidebars|netlify|vercel|deploy|readme)/i.test(filePath);
}

function documentationContentSignal(text: string): boolean {
  return /@docusaurus|docusaurus\s+(build|serve|start|deploy|docs:version)|sidebars?|themeConfig|navbar|footer|i18n|locales|algolia|sitemap|MDX|\.mdx|docsVersion|editUrl|GitHub Pages|Netlify|Vercel/i.test(text);
}

function documentationSiteConfigs(sourceFiles: DocumentationSourceFile[]): DocumentationReport["siteConfigs"] {
  const rows: DocumentationReport["siteConfigs"] = [];
  for (const source of sourceFiles) {
    const base = path.basename(source.filePath).toLowerCase();
    const push = (configType: DocumentationReport["siteConfigs"][number]["configType"], readiness: DocumentationReport["siteConfigs"][number]["readiness"], evidence: string) => {
      rows.push({ filePath: source.filePath, configType, readiness, evidence, sourceHref: source.sourceHref });
    };
    if (/^docusaurus\.config\.[cm]?[jt]s$/.test(base)) push("docusaurus-config", "ready", `${source.filePath} is a Docusaurus site configuration file.`);
    if (/^package\.json$/.test(base) && /@docusaurus|docusaurus\s+(start|build|serve|deploy|docs:version)/i.test(source.text)) push("package-script", "ready", `${source.filePath} references Docusaurus dependencies or commands.`);
    if (/^sidebars(\.[cm]?[jt]s|\.json)$/.test(base)) push("sidebar", "ready", `${source.filePath} defines documentation sidebar navigation.`);
    if (/themeConfig|navbar|footer|colorMode|prism/i.test(source.text) && /^docusaurus\.config\./i.test(base)) push("theme-config", "ready", `${source.filePath} contains themeConfig navigation or theme settings.`);
    if (rows.length < 140 && /@docusaurus|themeConfig|sidebars?/i.test(source.text) && !rows.some((item) => item.filePath === source.filePath)) push("unknown", "partial", `${source.filePath} contains Docusaurus-related text.`);
  }
  return rows.slice(0, 140);
}

function documentationContentSurfaces(walk: WalkResult, siteConfigs: DocumentationReport["siteConfigs"]): DocumentationReport["contentSurfaces"] {
  const hasConfig = siteConfigs.some((item) => ["docusaurus-config", "package-script"].includes(item.configType));
  const specs: Array<{ surface: DocumentationReport["contentSurfaces"][number]["surface"]; pattern: RegExp; evidence: string }> = [
    { surface: "docs", pattern: /(^|\/)docs\/.+\.mdx?$/i, evidence: "docs markdown/MDX files were detected." },
    { surface: "blog", pattern: /(^|\/)blog\/.+\.mdx?$/i, evidence: "blog markdown/MDX files were detected." },
    { surface: "pages", pattern: /(^|\/)(src\/pages|pages)\/.+\.(mdx?|[jt]sx?)$/i, evidence: "custom pages were detected." },
    { surface: "mdx", pattern: /\.mdx$/i, evidence: "MDX authoring files were detected." },
    { surface: "static-assets", pattern: /(^|\/)(static|public)\/.+/i, evidence: "static assets for documentation were detected." },
    { surface: "versioned-docs", pattern: /(^|\/)(versioned_docs|versioned_sidebars)\//i, evidence: "versioned docs or sidebars were detected." },
    { surface: "i18n", pattern: /(^|\/)i18n\//i, evidence: "i18n translation folders were detected." }
  ];
  return specs.map((spec) => {
    const count = walk.files.filter((file) => spec.pattern.test(file.relPath)).length;
    const readiness = count > 0 ? "ready" : hasConfig ? "external" : "missing";
    return {
      surface: spec.surface,
      count,
      readiness,
      evidence: count > 0 ? `${count} file(s): ${spec.evidence}` : `${spec.surface} content was not detected.`,
      relatedHref: "html/documentation.html"
    };
  });
}

function documentationNavigationSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["navigationSignals"] {
  const specs: Array<{ signal: DocumentationReport["navigationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "sidebar", pattern: /sidebars?|sidebarPath|docs:\s*\{[\s\S]*sidebar/i, evidence: "sidebar navigation evidence was detected." },
    { signal: "navbar", pattern: /navbar|Navbar/i, evidence: "navbar evidence was detected." },
    { signal: "footer", pattern: /footer/i, evidence: "footer evidence was detected." },
    { signal: "breadcrumbs", pattern: /breadcrumbs|hideBreadcrumbs/i, evidence: "breadcrumb control evidence was detected." },
    { signal: "toc", pattern: /tableOfContents|hide_table_of_contents|\btoc\b/i, evidence: "table-of-contents evidence was detected." },
    { signal: "edit-url", pattern: /editUrl|editCurrentVersion|editLocalizedFiles/i, evidence: "edit URL evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "navigation");
}

function documentationQualitySignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["qualitySignals"] {
  const specs: Array<{ signal: DocumentationReport["qualitySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "search", pattern: /algolia|localSearch|@easyops-cn\/docusaurus-search-local|search/i, evidence: "search integration evidence was detected." },
    { signal: "seo", pattern: /title:|tagline|metadata|headTags|onBrokenLinks|favicon/i, evidence: "SEO or site metadata evidence was detected." },
    { signal: "sitemap", pattern: /sitemap|@docusaurus\/plugin-sitemap/i, evidence: "sitemap evidence was detected." },
    { signal: "pwa", pattern: /pwa|@docusaurus\/plugin-pwa/i, evidence: "PWA plugin evidence was detected." },
    { signal: "analytics", pattern: /googleAnalytics|gtag|gtm|analytics|tag-manager/i, evidence: "analytics evidence was detected." },
    { signal: "theme", pattern: /themeConfig|@docusaurus\/theme|prism|colorMode/i, evidence: "theme customization evidence was detected." },
    { signal: "mdx", pattern: /MDX|\.mdx|@mdx/i, evidence: "MDX evidence was detected." },
    { signal: "typescript", pattern: /docusaurus\.config\.ts|sidebars\.ts|tsconfig|typescript/i, evidence: "TypeScript config evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "quality");
}

function documentationLocalizationSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["localizationSignals"] {
  const specs: Array<{ signal: DocumentationReport["localizationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "i18n-config", pattern: /i18n\s*:|locales|defaultLocale/i, evidence: "i18n config evidence was detected." },
    { signal: "locale-dropdown", pattern: /localeDropdown|type:\s*['"]localeDropdown/i, evidence: "locale dropdown evidence was detected." },
    { signal: "translation-folder", pattern: /(^|\/)i18n\/|translations|code\.json/i, evidence: "translation folder evidence was detected." },
    { signal: "crowdin", pattern: /crowdin/i, evidence: "Crowdin localization workflow evidence was detected." },
    { signal: "localized-config", pattern: /currentLocale|@docusaurus\/Translate|\btranslate\(/i, evidence: "localized config or translation helper evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "localization");
}

function documentationReleaseSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["releaseSignals"] {
  const specs: Array<{ signal: DocumentationReport["releaseSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "build-script", pattern: /"build"\s*:\s*"[^"]*docusaurus\s+build|docusaurus\s+build/i, evidence: "Docusaurus build script evidence was detected." },
    { signal: "serve-script", pattern: /"serve"\s*:\s*"[^"]*docusaurus\s+serve|docusaurus\s+serve|docusaurus\s+start/i, evidence: "serve/start script evidence was detected." },
    { signal: "deploy-script", pattern: /"deploy"\s*:\s*"[^"]*docusaurus\s+deploy|docusaurus\s+deploy/i, evidence: "deploy script evidence was detected." },
    { signal: "github-pages", pattern: /gh-pages|GitHub Pages|GITHUB_TOKEN|peaceiris|actions\/deploy-pages/i, evidence: "GitHub Pages deploy evidence was detected." },
    { signal: "netlify", pattern: /netlify|deploy-preview/i, evidence: "Netlify deploy or preview evidence was detected." },
    { signal: "vercel", pattern: /vercel/i, evidence: "Vercel deploy evidence was detected." },
    { signal: "ci-preview", pattern: /pull_request|preview|artifact|pages:|upload-pages-artifact/i, evidence: "CI preview or artifact evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "release");
}

function documentationSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: DocumentationSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/documentation.html"
    };
  });
}

async function buildDatabaseReadinessReport(walk: WalkResult): Promise<DatabaseReadinessReport> {
  const sourceFiles = await databaseSourceFiles(walk);
  const schemaFiles = databaseSchemaFiles(sourceFiles);
  const datasourceSignals = databaseDatasourceSignals(schemaFiles, sourceFiles);
  const migrationSignals = databaseMigrationSignals(sourceFiles);
  const clientSignals = databaseClientSignals(sourceFiles);
  const configSignals = databaseConfigSignals(sourceFiles);
  const modelSignals = databaseModelSignals(sourceFiles);
  const hasPrismaText = sourceFiles.length > 0;
  const hasSchema = schemaFiles.length > 0;
  const hasPrismaPackage = configSignals.some((item) => item.signal === "package-script" && item.readiness === "ready");
  const hasMigration = migrationSignals.some((item) => ["migrations-folder", "migration-sql", "migrate-dev", "migrate-deploy"].includes(item.signal) && item.readiness === "ready");
  const hasGenerate = clientSignals.some((item) => item.signal === "client-generation" && item.readiness === "ready");
  const hasDatabaseUrl = configSignals.some((item) => item.signal === "database-url" && item.readiness === "ready");
  const hasSeed = configSignals.some((item) => item.signal === "seed" && item.readiness === "ready");
  const hasClientUse = clientSignals.some((item) => item.signal === "prisma-client" && item.readiness === "ready");

  const riskQueue: DatabaseReadinessReport["riskQueue"] = [];
  if (hasPrismaPackage && !hasSchema) {
    riskQueue.push({
      priority: "high",
      action: "Add or locate a Prisma schema file before treating the database layer as documented.",
      why: "Prisma readiness starts with schema.prisma or an explicit schema path; package scripts alone do not show datasource, generator, or model shape.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasDatabaseUrl) {
    riskQueue.push({
      priority: "high",
      action: "Document the datasource URL boundary through prisma.config, DATABASE_URL, or an env example.",
      why: "Prisma CLI commands and generated clients need a reproducible datasource configuration before learners can run validate, generate, or migrate safely.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasGenerate) {
    riskQueue.push({
      priority: "high",
      action: "Add a Prisma Client generation command or explain how generation is triggered.",
      why: "The schema is not enough for application code; Prisma Client generation connects models to type-safe query code.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasMigration) {
    riskQueue.push({
      priority: "medium",
      action: "Choose a migration path such as migrate dev/deploy or document intentional db push usage.",
      why: "Prisma distinguishes declarative migrations from db push prototyping; RepoTutor should show which path protects database drift.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasClientUse) {
    riskQueue.push({
      priority: "medium",
      action: "Point learners to the runtime code that imports PrismaClient or a generated client output.",
      why: "Schema and migrations explain structure, but application learning needs to see where queries enter the runtime.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasSeed) {
    riskQueue.push({
      priority: "low",
      action: "Add a seed command or sample data note when local learning depends on database content.",
      why: "A generated client can connect successfully while the learner still has no realistic data to inspect.",
      relatedHref: "html/database-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasPrismaText ? "Run Prisma commands on the original source tree before treating this report as database approval." : "If this repository later adds a database layer, rerun RepoTutor to populate Prisma readiness.",
    why: "RepoTutor records static database readiness only; it does not connect to databases, run migrations, introspect schemas, generate clients, or seed data.",
    relatedHref: "html/database-readiness.html"
  });

  return {
    summary: `Prisma식 database readiness report: schema ${schemaFiles.length}개, datasource signal ${datasourceSignals.length}개, migration signal ${migrationSignals.length}개, client signal ${clientSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Prisma schema datasource generator model migrate generate db push seed PrismaClient DATABASE_URL driver adapter migrations",
    schemaFiles,
    datasourceSignals,
    migrationSignals,
    clientSignals,
    configSignals,
    modelSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx prisma validate", purpose: "Validate Prisma schema syntax and datasource/generator configuration." },
      { command: "npx prisma format", purpose: "Format schema.prisma so models, relations, and attributes are easier to inspect." },
      { command: "npx prisma generate", purpose: "Generate Prisma Client from the schema before checking runtime query code." },
      { command: "npx prisma migrate dev", purpose: "Create and apply a development migration against a safe local database." },
      { command: "npx prisma migrate deploy", purpose: "Apply committed migrations in deployment or CI environments." },
      { command: "npx prisma db seed", purpose: "Load seed data when local learning or tests need realistic rows." },
      { command: "npx prisma studio", purpose: "Open a database GUI for manual inspection after the datasource is safe." }
    ],
    learnerNextSteps: [
      "Start with schema.prisma: confirm datasource provider, generator output, model count, IDs, relations, and indexes.",
      "Separate prototype db push workflows from committed migration workflows before changing shared databases.",
      "Trace PrismaClient imports or generated client output to see where application code begins database queries.",
      "RepoTutor does not run Prisma commands, connect to databases, or generate clients; run the recommended commands on the original source tree."
    ]
  };
}

type DatabaseSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function databaseSourceFiles(walk: WalkResult): Promise<DatabaseSourceFile[]> {
  const files: DatabaseSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !databaseInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!databasePathSignal(file.relPath) && !databaseContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function databaseInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(schema\.prisma|prisma\.config\.[cm]?[jt]s|package\.json|docker-compose\.ya?ml|compose\.ya?ml|\.env\.example|\.env\.sample|README\.md)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(^|\/)(prisma|migrations|db|database|seed|seeds)\//i.test(filePath)
    || /\.(prisma|sql|[cm]?[jt]sx?|json|ya?ml|md)$/i.test(filePath);
}

function databasePathSignal(filePath: string): boolean {
  return /(schema\.prisma|prisma\.config|prisma\/|migrations\/|migration\.sql|seed|database|db\/|docker-compose|compose\.ya?ml|\.env\.example|\.env\.sample)/i.test(filePath);
}

function databaseContentSignal(text: string): boolean {
  return /PrismaClient|@prisma\/client|\bprisma\s+(validate|format|generate|migrate|db|studio)\b|schema\.prisma|datasource\s+\w+|generator\s+\w+|DATABASE_URL|provider\s*=|prisma\/config|defineConfig|migrations|seed/i.test(text);
}

function databaseSchemaFiles(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["schemaFiles"] {
  return sourceFiles
    .filter((source) => path.basename(source.filePath).toLowerCase() === "schema.prisma")
    .slice(0, 120)
    .map((source) => {
      const datasourceCount = countMatches(source.text, /\bdatasource\s+\w+\s*\{/g);
      const generatorCount = countMatches(source.text, /\bgenerator\s+\w+\s*\{/g);
      const modelCount = countMatches(source.text, /\bmodel\s+\w+\s*\{/g);
      const provider = normalizeDatabaseProvider(firstMatch(source.text, /provider\s*=\s*"([^"]+)"/i));
      return {
        filePath: source.filePath,
        provider,
        datasourceCount,
        generatorCount,
        modelCount,
        readiness: datasourceCount > 0 && generatorCount > 0 && modelCount > 0 ? "ready" : datasourceCount > 0 || generatorCount > 0 || modelCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${datasourceCount} datasource block(s), ${generatorCount} generator block(s), and ${modelCount} model block(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function databaseDatasourceSignals(schemaFiles: DatabaseReadinessReport["schemaFiles"], sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["datasourceSignals"] {
  const providers: DatabaseReadinessReport["datasourceSignals"][number]["provider"][] = ["postgresql", "mysql", "sqlite", "sqlserver", "mongodb", "cockroachdb", "mariadb"];
  return providers.map((provider) => {
    const schema = schemaFiles.find((item) => item.provider === provider);
    const source = sourceFiles.find((item) => new RegExp(`provider\\s*=\\s*[\"']${provider}[\"']|${provider}`, "i").test(item.text));
    return {
      provider,
      readiness: schema ? "ready" : source ? "partial" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: schema ? `${schema.filePath} declares datasource provider ${provider}.` : source ? `${source.filePath} references ${provider}.` : `${provider} datasource evidence was not detected.`,
      relatedHref: schema?.sourceHref ?? source?.sourceHref ?? "html/database-readiness.html"
    };
  });
}

function databaseMigrationSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["migrationSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["migrationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "migrations-folder", pattern: /(^|\/)migrations\/|migrations\s*:/i, evidence: "migrations folder or configured migration path evidence was detected." },
    { signal: "migration-sql", pattern: /migration\.sql|CREATE TABLE|ALTER TABLE|DROP TABLE/i, evidence: "SQL migration file evidence was detected." },
    { signal: "migration-lock", pattern: /migration_lock\.toml/i, evidence: "Prisma migration lock evidence was detected." },
    { signal: "migrate-dev", pattern: /prisma\s+migrate\s+dev|migrate dev/i, evidence: "development migration command evidence was detected." },
    { signal: "migrate-deploy", pattern: /prisma\s+migrate\s+deploy|migrate deploy/i, evidence: "deployment migration command evidence was detected." },
    { signal: "db-push", pattern: /prisma\s+db\s+push|db push/i, evidence: "db push workflow evidence was detected." },
    { signal: "introspection", pattern: /prisma\s+db\s+pull|introspect|introspection/i, evidence: "database introspection evidence was detected." },
    { signal: "schema-drift", pattern: /schema drift|drift detected|database is out of sync|migrate diff/i, evidence: "schema drift detection evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "migration");
}

function databaseClientSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["clientSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["clientSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prisma-client", pattern: /PrismaClient|@prisma\/client|generated\/(?:prisma\/)?client/i, evidence: "PrismaClient runtime usage evidence was detected." },
    { signal: "client-generation", pattern: /prisma\s+generate|generator\s+client|generate"/i, evidence: "Prisma Client generation evidence was detected." },
    { signal: "custom-output", pattern: /output\s*=|generated\/client|generated\/prisma/i, evidence: "custom generated client output evidence was detected." },
    { signal: "prisma-client-js", pattern: /prisma-client-js|provider\s*=\s*"prisma-client-js"/i, evidence: "traditional prisma-client-js generator evidence was detected." },
    { signal: "driver-adapter", pattern: /adapter|@prisma\/adapter-|PrismaPg|driver adapter/i, evidence: "driver adapter evidence was detected." },
    { signal: "typed-query", pattern: /typedSql|typed-sql|queryRaw|executeRaw/i, evidence: "typed/raw query surface evidence was detected." },
    { signal: "studio", pattern: /prisma\s+studio|Prisma Studio|studio"/i, evidence: "Prisma Studio evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "client");
}

function databaseConfigSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["configSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["configSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prisma-config", pattern: /prisma\.config\.[cm]?[jt]s|defineConfig|prisma\/config/i, evidence: "prisma.config evidence was detected." },
    { signal: "database-url", pattern: /DATABASE_URL|datasource:\s*\{|env\(['"]DATABASE_URL|url\s*:\s*env/i, evidence: "database URL boundary evidence was detected." },
    { signal: "dotenv", pattern: /dotenv|@dotenvx|\.env/i, evidence: "dotenv loading or env example evidence was detected." },
    { signal: "seed", pattern: /prisma\s+db\s+seed|"seed"\s*:|seed\.([cm]?[jt]s|ts|js)|seed-data/i, evidence: "seed workflow evidence was detected." },
    { signal: "package-script", pattern: /"prisma"\s*:|"dbpush"\s*:|"generate"\s*:\s*"[^"]*prisma|@prisma\/client|\bprisma\b/i, evidence: "package Prisma dependency or script evidence was detected." },
    { signal: "docker-compose", pattern: /docker-compose|compose\.ya?ml|postgres:|mysql:|mariadb:|mongo:/i, evidence: "local database service evidence was detected." },
    { signal: "env-example", pattern: /\.env\.example|\.env\.sample|DATABASE_URL=/i, evidence: "env example evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "config");
}

function databaseModelSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["modelSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["modelSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "model", pattern: /\bmodel\s+\w+\s*\{/i, evidence: "model block evidence was detected." },
    { signal: "relation", pattern: /@relation|\w+\s+\w+\[\]/i, evidence: "relation evidence was detected." },
    { signal: "id", pattern: /@id|@@id/i, evidence: "primary key evidence was detected." },
    { signal: "unique", pattern: /@unique|@@unique/i, evidence: "unique constraint evidence was detected." },
    { signal: "index", pattern: /@@index|@@fulltext|@@map/i, evidence: "index or mapped model evidence was detected." },
    { signal: "enum", pattern: /\benum\s+\w+\s*\{/i, evidence: "enum evidence was detected." },
    { signal: "native-type", pattern: /@db\./i, evidence: "native database type evidence was detected." },
    { signal: "default", pattern: /@default\(/i, evidence: "default value evidence was detected." },
    { signal: "map", pattern: /@map|@@map/i, evidence: "database mapping evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "model");
}

function databaseSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: DatabaseSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/database-readiness.html"
    };
  });
}

function normalizeDatabaseProvider(value: string | null): DatabaseReadinessReport["schemaFiles"][number]["provider"] {
  const normalized = value?.toLowerCase();
  if (normalized === "postgresql" || normalized === "postgres") return "postgresql";
  if (normalized === "mysql") return "mysql";
  if (normalized === "sqlite") return "sqlite";
  if (normalized === "sqlserver" || normalized === "mssql") return "sqlserver";
  if (normalized === "mongodb" || normalized === "mongo") return "mongodb";
  if (normalized === "cockroachdb") return "cockroachdb";
  if (normalized === "mariadb") return "mariadb";
  return "unknown";
}

async function buildCiCdReport(walk: WalkResult): Promise<CiCdReport> {
  const sourceFiles = await ciCdSourceFiles(walk);
  const workflowFiles = ciCdWorkflowFiles(sourceFiles);
  const triggerSignals = ciCdTriggerSignals(sourceFiles);
  const jobSignals = ciCdJobSignals(sourceFiles);
  const securitySignals = ciCdSecuritySignals(sourceFiles, workflowFiles);
  const deliverySignals = ciCdDeliverySignals(sourceFiles);
  const platformSignals = ciCdPlatformSignals(sourceFiles);
  const hasWorkflow = workflowFiles.length > 0;
  const hasPushOrPr = triggerSignals.some((item) => ["push", "pull_request"].includes(item.trigger) && item.readiness === "ready");
  const hasManualOrSchedule = triggerSignals.some((item) => ["workflow_dispatch", "schedule"].includes(item.trigger) && item.readiness === "ready");
  const hasJobs = jobSignals.some((item) => item.signal === "jobs" && item.readiness === "ready")
    && jobSignals.some((item) => item.signal === "runs-on" && item.readiness === "ready");
  const hasPermissions = securitySignals.some((item) => item.signal === "permissions" && item.readiness === "ready");
  const hasDeployment = deliverySignals.some((item) => ["deployment", "release", "package-publish"].includes(item.signal) && item.readiness === "ready");
  const hasEnvironment = securitySignals.some((item) => item.signal === "environment" && item.readiness === "ready")
    || deliverySignals.some((item) => item.signal === "environment-protection" && item.readiness === "ready");
  const hasConcurrency = deliverySignals.some((item) => item.signal === "concurrency" && item.readiness === "ready");
  const hasCacheOrArtifacts = deliverySignals.some((item) => ["cache", "artifact-upload", "artifact-download"].includes(item.signal) && item.readiness === "ready");
  const usesSecrets = securitySignals.some((item) => item.signal === "secrets" && item.readiness === "ready");
  const hasOidc = securitySignals.some((item) => ["id-token-write", "oidc"].includes(item.signal) && item.readiness === "ready");
  const hasPullRequestTarget = securitySignals.some((item) => item.signal === "pull-request-target" && item.readiness === "partial");

  const riskQueue: CiCdReport["riskQueue"] = [];
  if (!hasWorkflow) {
    riskQueue.push({
      priority: "high",
      action: "Add at least one GitHub Actions workflow under .github/workflows before claiming CI/CD readiness.",
      why: "GitHub Actions workflow syntax requires YAML files in .github/workflows; package scripts alone do not prove automation.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasWorkflow && !hasPushOrPr) {
    riskQueue.push({
      priority: "high",
      action: "Trigger CI on push or pull_request events.",
      why: "GitHub's CI guidance centers on building and testing code when commits or pull requests enter the shared repository.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasWorkflow && !hasJobs) {
    riskQueue.push({
      priority: "high",
      action: "Declare jobs with runs-on targets and executable steps.",
      why: "Workflow files are only useful when they define jobs that can run on GitHub-hosted or self-hosted runners.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasWorkflow && !hasPermissions) {
    riskQueue.push({
      priority: "medium",
      action: "Set explicit workflow or job permissions for GITHUB_TOKEN.",
      why: "GitHub recommends setting the token permissions needed by the workflow instead of relying on broad defaults.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasDeployment && !hasEnvironment) {
    riskQueue.push({
      priority: "medium",
      action: "Use environments or deployment protection rules for deploy jobs.",
      why: "GitHub deployments and environments can require approval, restrict branches, and scope environment secrets before rollout.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasDeployment && !hasConcurrency) {
    riskQueue.push({
      priority: "medium",
      action: "Add concurrency groups around deployment workflows.",
      why: "GitHub Actions concurrency prevents overlapping deployments to the same target environment.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (usesSecrets && !hasOidc) {
    riskQueue.push({
      priority: "low",
      action: "Prefer OIDC for cloud deployment credentials where the provider supports it.",
      why: "GitHub's OIDC guidance reduces long-lived cloud secrets and requires explicit trust conditions.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasWorkflow && !hasCacheOrArtifacts) {
    riskQueue.push({
      priority: "low",
      action: "Add cache or artifact steps when build outputs, test reports, screenshots, or dependency downloads matter.",
      why: "GitHub Actions distinguishes dependency caching from workflow artifacts that persist data after jobs finish.",
      relatedHref: "html/ci-cd.html"
    });
  }
  if (hasPullRequestTarget) {
    riskQueue.push({
      priority: "high",
      action: "Review pull_request_target workflows for untrusted code checkout and secret exposure.",
      why: "pull_request_target can run with privileged repository context and needs stricter review than ordinary pull_request CI.",
      relatedHref: "html/ci-cd.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasWorkflow ? "Run workflow validation and a safe branch CI run before treating this report as CI/CD approval." : "If this repository later adds GitHub Actions, rerun RepoTutor to populate CI/CD readiness.",
    why: "RepoTutor records static GitHub Actions readiness only; it does not execute workflows, validate YAML semantics, or call GitHub APIs.",
    relatedHref: "html/ci-cd.html"
  });

  return {
    summary: `GitHub Actions식 CI/CD readiness report: workflow ${workflowFiles.length}개, trigger signal ${triggerSignals.length}개, job signal ${jobSignals.length}개, delivery signal ${deliverySignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "GitHub Actions workflow syntax events jobs permissions GITHUB_TOKEN OIDC cache artifacts concurrency environments deployments",
    workflowFiles,
    triggerSignals,
    jobSignals,
    securitySignals,
    deliverySignals,
    platformSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "gh workflow list", purpose: "List workflows visible to GitHub for the repository." },
      { command: "gh workflow view <workflow.yml>", purpose: "Inspect workflow metadata and dispatchability from GitHub's view." },
      { command: "gh run list --workflow <workflow.yml> --limit 10", purpose: "Check recent run status before trusting the static report." },
      { command: "act -n", purpose: "Dry-run GitHub Actions locally where nektos/act supports the workflow shape." },
      { command: "npx actionlint", purpose: "Validate workflow YAML syntax, expressions, and common GitHub Actions mistakes." },
      { command: "gh run watch", purpose: "Watch a live workflow run after pushing to a safe branch." }
    ],
    learnerNextSteps: [
      "Start with .github/workflows: identify trigger events, job names, runner labels, and the order imposed by needs.",
      "Separate CI jobs that build/test pull requests from CD jobs that deploy or publish artifacts.",
      "Review permissions, secrets, OIDC, environments, and concurrency before treating deploy jobs as safe.",
      "RepoTutor does not execute GitHub Actions or validate YAML semantics; run actionlint and a safe branch workflow before approval."
    ]
  };
}

type CiCdSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function ciCdSourceFiles(walk: WalkResult): Promise<CiCdSourceFile[]> {
  const files: CiCdSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !ciCdInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!ciCdPathSignal(file.relPath) && !ciCdContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function ciCdInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /^\.github\/actions\//i.test(filePath)
    || /^(package\.json|pnpm-workspace\.yaml|turbo\.json|nx\.json|README\.md|action\.ya?ml)$/i.test(base)
    || /(ci|cd|deploy|workflow|release|pipeline|build|test|publish)/i.test(filePath)
    || /\.(ya?ml|json|md|[cm]?[jt]sx?|sh)$/i.test(filePath);
}

function ciCdPathSignal(filePath: string): boolean {
  return /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(github\/actions|workflow|ci|cd|deploy|release|pipeline|publish|action\.ya?ml)/i.test(filePath);
}

function ciCdContentSignal(text: string): boolean {
  return /GitHub Actions|\.github\/workflows|workflow_dispatch|pull_request|repository_dispatch|GITHUB_TOKEN|id-token|actions\/checkout|actions\/cache|upload-artifact|download-artifact|runs-on|concurrency|environment:|gh workflow|actionlint/i.test(text);
}

function ciCdWorkflowFiles(sourceFiles: CiCdSourceFile[]): CiCdReport["workflowFiles"] {
  return sourceFiles
    .filter((source) => /^\.github\/workflows\/.+\.ya?ml$/i.test(source.filePath))
    .slice(0, 120)
    .map((source) => {
      const workflowName = firstMatch(source.text, /^\s*name\s*:\s*(.+)$/im)?.replace(/^["']|["']$/g, "").trim() ?? null;
      const triggerCount = ciCdTriggerCount(source.text);
      const jobCount = ciCdJobCount(source.text);
      return {
        filePath: source.filePath,
        workflowName,
        triggerCount,
        jobCount,
        readiness: triggerCount > 0 && jobCount > 0 ? "ready" : triggerCount > 0 || jobCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${triggerCount} trigger signal(s) and ${jobCount} job candidate(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function ciCdTriggerCount(text: string): number {
  const triggers = ["push", "pull_request", "workflow_dispatch", "schedule", "repository_dispatch", "workflow_call", "release", "deployment"];
  return triggers.filter((trigger) => new RegExp(`(^|\\n)\\s*${trigger}\\s*:|\\bon\\s*:\\s*\\[[^\\]]*${trigger}|\\bon\\s*:\\s*${trigger}\\b`, "i").test(text)).length;
}

function ciCdJobCount(text: string): number {
  const jobsBlock = text.match(/^jobs\s*:\s*([\s\S]*)/im)?.[1] ?? "";
  const matches = [...jobsBlock.matchAll(/^\s{2}[A-Za-z0-9_-]+\s*:\s*(?:\n|$)/gm)];
  return matches.length;
}

function ciCdTriggerSignals(sourceFiles: CiCdSourceFile[]): CiCdReport["triggerSignals"] {
  const specs: Array<{ trigger: CiCdReport["triggerSignals"][number]["trigger"]; pattern: RegExp; evidence: string }> = [
    { trigger: "push", pattern: /(^|\n)\s*push\s*:|\bon\s*:\s*\[[^\]]*push|\bon\s*:\s*push\b/i, evidence: "push trigger evidence was detected." },
    { trigger: "pull_request", pattern: /(^|\n)\s*pull_request\s*:|\bon\s*:\s*\[[^\]]*pull_request|\bon\s*:\s*pull_request\b/i, evidence: "pull_request trigger evidence was detected." },
    { trigger: "workflow_dispatch", pattern: /workflow_dispatch/i, evidence: "manual workflow_dispatch trigger evidence was detected." },
    { trigger: "schedule", pattern: /(^|\n)\s*schedule\s*:|\bcron\s*:/i, evidence: "scheduled trigger evidence was detected." },
    { trigger: "repository_dispatch", pattern: /repository_dispatch/i, evidence: "repository_dispatch trigger evidence was detected." },
    { trigger: "workflow_call", pattern: /workflow_call/i, evidence: "reusable workflow_call trigger evidence was detected." },
    { trigger: "release", pattern: /(^|\n)\s*release\s*:|\bon\s*:\s*\[[^\]]*release|\bon\s*:\s*release\b/i, evidence: "release trigger evidence was detected." },
    { trigger: "deployment", pattern: /(^|\n)\s*deployment(_status)?\s*:|\bon\s*:\s*\[[^\]]*deployment/i, evidence: "deployment trigger evidence was detected." }
  ];
  return ciCdSignalFromSpecs(sourceFiles, specs, "trigger", "trigger");
}

function ciCdJobSignals(sourceFiles: CiCdSourceFile[]): CiCdReport["jobSignals"] {
  const specs: Array<{ signal: CiCdReport["jobSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "jobs", pattern: /(^|\n)\s*jobs\s*:/i, evidence: "jobs block evidence was detected." },
    { signal: "runs-on", pattern: /(^|\n)\s*runs-on\s*:/i, evidence: "runner selection evidence was detected." },
    { signal: "steps", pattern: /(^|\n)\s*steps\s*:/i, evidence: "job steps evidence was detected." },
    { signal: "uses", pattern: /(^|\n)\s*uses\s*:/i, evidence: "action or reusable workflow usage evidence was detected." },
    { signal: "run", pattern: /(^|\n)\s*run\s*:/i, evidence: "shell command step evidence was detected." },
    { signal: "needs", pattern: /(^|\n)\s*needs\s*:/i, evidence: "job dependency ordering evidence was detected." },
    { signal: "matrix", pattern: /strategy\s*:|matrix\s*:/i, evidence: "matrix strategy evidence was detected." },
    { signal: "services", pattern: /(^|\n)\s*services\s*:/i, evidence: "service container evidence was detected." },
    { signal: "container", pattern: /(^|\n)\s*container\s*:/i, evidence: "job container evidence was detected." },
    { signal: "defaults", pattern: /(^|\n)\s*defaults\s*:/i, evidence: "workflow/job defaults evidence was detected." },
    { signal: "timeout-minutes", pattern: /timeout-minutes\s*:/i, evidence: "timeout control evidence was detected." }
  ];
  return ciCdSignalFromSpecs(sourceFiles, specs, "job", "signal");
}

function ciCdSecuritySignals(sourceFiles: CiCdSourceFile[], workflowFiles: CiCdReport["workflowFiles"]): CiCdReport["securitySignals"] {
  const specs: Array<{ signal: CiCdReport["securitySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "permissions", pattern: /(^|\n)\s*permissions\s*:/i, evidence: "explicit GITHUB_TOKEN permissions evidence was detected." },
    { signal: "contents-read", pattern: /contents\s*:\s*read/i, evidence: "contents: read permission evidence was detected." },
    { signal: "id-token-write", pattern: /id-token\s*:\s*write/i, evidence: "OIDC id-token: write permission evidence was detected." },
    { signal: "secrets", pattern: /secrets\.|secrets\s*:|GITHUB_TOKEN|GH_TOKEN/i, evidence: "secrets or GITHUB_TOKEN usage evidence was detected." },
    { signal: "environment", pattern: /(^|\n)\s*environment\s*:/i, evidence: "environment-scoped job evidence was detected." },
    { signal: "pull-request-target", pattern: /pull_request_target/i, evidence: "privileged pull_request_target trigger evidence was detected." },
    { signal: "oidc", pattern: /OIDC|OpenID Connect|id-token|aws-actions\/configure-aws-credentials|azure\/login|google-github-actions\/auth/i, evidence: "OIDC authentication evidence was detected." }
  ];
  const rows = ciCdSignalFromSpecs(sourceFiles, specs, "security", "signal") as CiCdReport["securitySignals"];
  const usesLines = sourceFiles.flatMap((source) => [...source.text.matchAll(/^\s*uses\s*:\s*([^\s#]+)/gim)].map((match) => ({ source, value: match[1] })));
  const pinnedCount = usesLines.filter((item) => /@[0-9a-f]{40}$/i.test(item.value)).length;
  rows.push({
    signal: "pinned-actions",
    readiness: usesLines.length === 0 ? (workflowFiles.length > 0 ? "external" : "missing") : pinnedCount === usesLines.length ? "ready" : "partial",
    evidence: usesLines.length === 0 ? "action pinning evidence was not detected." : `${pinnedCount}/${usesLines.length} uses references appear pinned to full commit SHAs.`,
    relatedHref: usesLines[0]?.source.sourceHref ?? "html/ci-cd.html"
  });
  return rows.map((item) => item.signal === "pull-request-target" && item.readiness === "ready" ? { ...item, readiness: "partial" } : item);
}

function ciCdDeliverySignals(sourceFiles: CiCdSourceFile[]): CiCdReport["deliverySignals"] {
  const specs: Array<{ signal: CiCdReport["deliverySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "cache", pattern: /actions\/cache|cache-dependency-path|setup-node[\s\S]{0,200}cache\s*:|dependency caching/i, evidence: "dependency cache evidence was detected." },
    { signal: "artifact-upload", pattern: /actions\/upload-artifact|upload-artifact/i, evidence: "artifact upload evidence was detected." },
    { signal: "artifact-download", pattern: /actions\/download-artifact|download-artifact/i, evidence: "artifact download evidence was detected." },
    { signal: "concurrency", pattern: /(^|\n)\s*concurrency\s*:/i, evidence: "workflow or job concurrency evidence was detected." },
    { signal: "environment-protection", pattern: /environment\s*:|required reviewers|deployment protection/i, evidence: "environment or deployment protection evidence was detected." },
    { signal: "deployment", pattern: /deploy|deployment|environment\s*:/i, evidence: "deployment workflow evidence was detected." },
    { signal: "release", pattern: /release|gh release|semantic-release|release-please|changesets/i, evidence: "release workflow evidence was detected." },
    { signal: "package-publish", pattern: /npm publish|pnpm publish|docker\/build-push-action|ghcr\.io|packages:\s*write|publish/i, evidence: "package publish evidence was detected." }
  ];
  return ciCdSignalFromSpecs(sourceFiles, specs, "delivery", "signal");
}

function ciCdPlatformSignals(sourceFiles: CiCdSourceFile[]): CiCdReport["platformSignals"] {
  const specs: Array<{ signal: CiCdReport["platformSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "github-hosted-runner", pattern: /ubuntu-latest|macos-latest|windows-latest/i, evidence: "GitHub-hosted runner label evidence was detected." },
    { signal: "self-hosted-runner", pattern: /self-hosted/i, evidence: "self-hosted runner label evidence was detected." },
    { signal: "linux", pattern: /ubuntu-|linux/i, evidence: "Linux runner evidence was detected." },
    { signal: "macos", pattern: /macos-/i, evidence: "macOS runner evidence was detected." },
    { signal: "windows", pattern: /windows-/i, evidence: "Windows runner evidence was detected." },
    { signal: "node-setup", pattern: /actions\/setup-node|node-version|pnpm\/action-setup|npm ci|pnpm install/i, evidence: "Node setup evidence was detected." },
    { signal: "python-setup", pattern: /actions\/setup-python|python-version|pip install|uv sync/i, evidence: "Python setup evidence was detected." },
    { signal: "docker-build", pattern: /docker\/build-push-action|docker build|buildx|Dockerfile/i, evidence: "Docker build evidence was detected." }
  ];
  return ciCdSignalFromSpecs(sourceFiles, specs, "platform", "signal");
}

function ciCdSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: CiCdSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/ci-cd.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildUnitTestReport(walk: WalkResult): Promise<UnitTestReport> {
  const sourceFiles = await unitTestSourceFiles(walk);
  const testFiles = unitTestFiles(sourceFiles);
  const configFiles = unitTestConfigFiles(sourceFiles);
  const assertionSignals = unitTestAssertionSignals(sourceFiles);
  const mockSignals = unitTestMockSignals(sourceFiles);
  const coverageSignals = unitTestCoverageSignals(sourceFiles);
  const environmentSignals = unitTestEnvironmentSignals(sourceFiles);
  const reportingSignals = unitTestReportingSignals(sourceFiles);
  const hasTestFiles = testFiles.length > 0;
  const hasConfig = configFiles.some((item) => item.readiness === "ready" || item.readiness === "partial");
  const hasAssertions = assertionSignals.some((item) => item.readiness === "ready");
  const hasMocks = mockSignals.some((item) => ["vi-fn", "vi-mock", "vi-spyOn", "module-mock", "request-mock", "fake-timers"].includes(item.signal) && item.readiness === "ready");
  const hasMockReset = mockSignals.some((item) => item.signal === "mock-reset" && item.readiness === "ready");
  const hasCoverage = coverageSignals.some((item) => item.readiness === "ready");
  const hasDomEnvironment = environmentSignals.some((item) => ["jsdom", "happy-dom", "browser-mode"].includes(item.signal) && item.readiness === "ready");
  const hasDomLookingTests = sourceFiles.some((source) => unitTestPathSignal(source.filePath) && /\b(document|window|HTMLElement|@testing-library|render\s*\()/i.test(source.text));
  const hasReporter = reportingSignals.some((item) => ["reporter", "junit", "json", "html", "ui"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: UnitTestReport["riskQueue"] = [];
  if (!hasTestFiles) {
    riskQueue.push({
      priority: "high",
      action: "Add focused unit or component test files before claiming test readiness.",
      why: "Vitest discovers files such as *.test.ts, *.spec.ts, tests/, and __tests__/; this scan did not find test files.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (!hasConfig) {
    riskQueue.push({
      priority: "medium",
      action: "Add a test script or Vitest/Vite test configuration.",
      why: "A package test script, vitest.config file, or Vite test block makes the expected runner and environment explicit.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (hasTestFiles && !hasAssertions) {
    riskQueue.push({
      priority: "medium",
      action: "Add explicit assertions to test files.",
      why: "Vitest can run test bodies without meaningful checks; expect/assert and matcher usage proves behavior is verified.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (hasMocks && !hasMockReset) {
    riskQueue.push({
      priority: "low",
      action: "Reset or restore mocks between tests.",
      why: "Vitest mocking guidance warns that shared mocks, spies, and fake timers can leak state across tests.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (!hasCoverage) {
    riskQueue.push({
      priority: "medium",
      action: "Add coverage reporting for unit tests.",
      why: "Vitest supports v8 and istanbul coverage providers, but this repository has no static coverage signal.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (hasDomLookingTests && !hasDomEnvironment) {
    riskQueue.push({
      priority: "medium",
      action: "Configure jsdom, happy-dom, or browser mode for DOM-oriented tests.",
      why: "Vitest's default environment is Node; DOM APIs need an explicit compatible environment.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (hasTestFiles && !hasReporter) {
    riskQueue.push({
      priority: "low",
      action: "Add machine-readable reporters when CI or dashboards need test results.",
      why: "Vitest can emit JUnit, JSON, HTML, and UI outputs, but no static reporting signal was found.",
      relatedHref: "html/unit-tests.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasTestFiles ? "Run the unit test suite before treating this static report as approval." : "If this repository later adds Vitest tests, rerun RepoTutor to populate unit test readiness.",
    why: "RepoTutor records static unit-test readiness only; it does not execute tests, measure coverage, update snapshots, or validate jsdom/browser behavior.",
    relatedHref: "html/unit-tests.html"
  });

  return {
    summary: `Vitest-style unit test readiness report: test files ${testFiles.length}개, config files ${configFiles.length}개, assertion signals ${assertionSignals.length}개, coverage signals ${coverageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Vitest test files config coverage v8 istanbul snapshots mocks jsdom happy-dom browser mode projects reporters",
    testFiles,
    configFiles,
    assertionSignals,
    mockSignals,
    coverageSignals,
    environmentSignals,
    reportingSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx vitest run", purpose: "Run unit tests once in CI-style run mode." },
      { command: "npx vitest --watch", purpose: "Use watch mode while developing tests locally." },
      { command: "npx vitest run --coverage", purpose: "Generate coverage with the configured v8 or istanbul provider." },
      { command: "npx vitest --ui", purpose: "Open Vitest UI for interactive test inspection." },
      { command: "npx vitest --reporter=junit", purpose: "Emit CI-friendly test results for dashboards or annotations." },
      { command: "npx vitest --update", purpose: "Update snapshots intentionally after reviewing behavior changes." }
    ],
    learnerNextSteps: [
      "Start with package.json and vitest.config: identify the test command, environment, coverage provider, setup files, and reporter outputs.",
      "Open each test file and separate arrange/act/assert lines, mock setup, fixture data, and snapshot assertions.",
      "Check whether DOM or browser tests declare jsdom, happy-dom, or browser mode instead of relying on Node defaults.",
      "RepoTutor does not execute tests or measure real coverage; run Vitest before treating this as test approval."
    ]
  };
}

type UnitTestSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function unitTestSourceFiles(walk: WalkResult): Promise<UnitTestSourceFile[]> {
  const files: UnitTestSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !unitTestInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!unitTestPathSignal(file.relPath) && !unitTestContentSignal(text) && path.basename(file.relPath) !== "package.json") continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function unitTestInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /(^|\/)(__tests__|tests?|spec|fixtures?|mocks?|__mocks__|snapshots?)\//i.test(filePath)
    || /\.(test|spec)\.[cm]?[jt]sx?$/i.test(base)
    || /\.snap$/i.test(base)
    || /^vitest\.config\.[cm]?[jt]s$/i.test(base)
    || /^vitest\.workspace\.[cm]?[jt]s(on)?$/i.test(base)
    || /^vite\.config\.[cm]?[jt]s$/i.test(base)
    || /^(package\.json|pnpm-workspace\.yaml|README\.md)$/i.test(base)
    || /(test|spec|vitest|jest|mocha|ava|coverage|snapshot|setupTests|setup-tests)/i.test(filePath)
    || /\.(json|md|ya?ml|[cm]?[jt]sx?)$/i.test(filePath);
}

function unitTestPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /(^|\/)(__tests__|tests?|spec|fixtures?|mocks?|__mocks__|snapshots?)\//i.test(filePath)
    || /\.(test|spec)\.[cm]?[jt]sx?$/i.test(base)
    || /\.snap$/i.test(base)
    || /^vitest\.(config|workspace)\./i.test(base)
    || /^vite\.config\./i.test(base)
    || /(vitest|jest|mocha|ava|coverage|snapshot|setupTests|setup-tests)/i.test(filePath);
}

function unitTestContentSignal(text: string): boolean {
  return /\b(vitest|jest|mocha|ava|node:test|describe\s*\(|it\s*\(|test\s*\(|expect\s*\(|assert\.|vi\.|toMatchSnapshot|jsdom|happy-dom|coverage|@testing-library)\b/i.test(text);
}

function unitTestFiles(sourceFiles: UnitTestSourceFile[]): UnitTestReport["testFiles"] {
  return sourceFiles
    .filter((source) => unitTestPathSignal(source.filePath) && (/\.(test|spec)\.[cm]?[jt]sx?$/i.test(path.basename(source.filePath)) || /(^|\/)(__tests__|tests?|spec)\//i.test(source.filePath)))
    .slice(0, 160)
    .map((source) => {
      const testCount = countMatches(source.text, /\b(describe|it|test)\s*\(/g);
      const assertionCount = unitTestAssertionCount(source.text);
      return {
        filePath: source.filePath,
        framework: inferUnitTestFramework(source),
        testCount,
        assertionCount,
        readiness: testCount > 0 && assertionCount > 0 ? "ready" : testCount > 0 || assertionCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${testCount} test block candidate(s) and ${assertionCount} assertion candidate(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function unitTestConfigFiles(sourceFiles: UnitTestSourceFile[]): UnitTestReport["configFiles"] {
  return sourceFiles
    .filter((source) => unitTestConfigType(source.filePath, source.text) !== "unknown" || path.basename(source.filePath) === "package.json")
    .slice(0, 120)
    .map((source) => {
      const configType = unitTestConfigType(source.filePath, source.text);
      const hasTestScript = path.basename(source.filePath) === "package.json" && /"scripts"\s*:\s*\{[\s\S]*"test"\s*:\s*"[^"]+"/i.test(source.text);
      const readiness = configType === "package-script" ? (hasTestScript ? "ready" : "missing") : configType === "unknown" ? "missing" : "ready";
      return {
        filePath: source.filePath,
        configType: configType === "unknown" && path.basename(source.filePath) === "package.json" ? "package-script" : configType,
        readiness,
        evidence: configType === "package-script" || path.basename(source.filePath) === "package.json"
          ? (hasTestScript ? `${source.filePath} declares a package test script.` : `${source.filePath} does not declare a package test script.`)
          : `${source.filePath} matches ${configType} static configuration.`,
        sourceHref: source.sourceHref
      };
    });
}

function unitTestConfigType(filePath: string, text: string): UnitTestReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath);
  if (/^vitest\.config\.[cm]?[jt]s$/i.test(base)) return "vitest-config";
  if (/^vite\.config\.[cm]?[jt]s$/i.test(base) && /\btest\s*:/i.test(text)) return "vite-config-test";
  if (base === "package.json") return "package-script";
  if (/^vitest\.workspace\./i.test(base) || path.basename(filePath) === "pnpm-workspace.yaml") return "workspace";
  if (/(setupTests|setup-tests|test-setup|setup\.[cm]?[jt]s)/i.test(filePath)) return "setup-file";
  return "unknown";
}

function inferUnitTestFramework(source: UnitTestSourceFile): UnitTestReport["testFiles"][number]["framework"] {
  if (/vitest|from\s+["']vitest["']|vi\./i.test(source.text)) return "vitest";
  if (/jest|from\s+["']@jest\/globals["']/i.test(source.text)) return "jest";
  if (/mocha|from\s+["']mocha["']/i.test(source.text)) return "mocha";
  if (/from\s+["']ava["']|\bava\b/i.test(source.text)) return "ava";
  if (/node:test|from\s+["']node:test["']/i.test(source.text)) return "node-test";
  return "unknown";
}

function unitTestAssertionCount(text: string): number {
  return countMatches(text, /\bexpect\s*\(|\bassert\.|\.to(Equal|Be|StrictEqual|MatchSnapshot|Throw|Have)|\bthrows\s*\(|\.resolves\b|\.rejects\b/g);
}

function unitTestAssertionSignals(sourceFiles: UnitTestSourceFile[]): UnitTestReport["assertionSignals"] {
  const specs: Array<{ assertion: UnitTestReport["assertionSignals"][number]["assertion"]; pattern: RegExp; evidence: string }> = [
    { assertion: "expect", pattern: /\bexpect\s*\(/i, evidence: "expect assertion evidence was detected." },
    { assertion: "assert", pattern: /\bassert\./i, evidence: "assert API evidence was detected." },
    { assertion: "toEqual", pattern: /\.to(Equal|StrictEqual)\s*\(/i, evidence: "deep equality matcher evidence was detected." },
    { assertion: "toBe", pattern: /\.to(Be|BeTruthy|BeFalsy|BeDefined|BeNull|BeUndefined)\s*\(/i, evidence: "identity/truthiness matcher evidence was detected." },
    { assertion: "toMatchSnapshot", pattern: /toMatch(Inline)?Snapshot\s*\(/i, evidence: "snapshot assertion evidence was detected." },
    { assertion: "throws", pattern: /toThrow\s*\(|\bthrows\s*\(/i, evidence: "throw assertion evidence was detected." },
    { assertion: "resolves", pattern: /\.resolves\b/i, evidence: "async resolves assertion evidence was detected." },
    { assertion: "rejects", pattern: /\.rejects\b/i, evidence: "async rejects assertion evidence was detected." },
    { assertion: "custom-matcher", pattern: /expect\.extend|toHave[A-Z][A-Za-z]+\s*\(/i, evidence: "custom matcher-style evidence was detected." }
  ];
  return unitTestSignalFromSpecs(sourceFiles, specs, "assertion", "assertion");
}

function unitTestMockSignals(sourceFiles: UnitTestSourceFile[]): UnitTestReport["mockSignals"] {
  const specs: Array<{ signal: UnitTestReport["mockSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "vi-fn", pattern: /\bvi\.fn\s*\(/i, evidence: "vi.fn mock evidence was detected." },
    { signal: "vi-mock", pattern: /\bvi\.mock\s*\(/i, evidence: "vi.mock module mock evidence was detected." },
    { signal: "vi-spyOn", pattern: /\bvi\.spyOn\s*\(/i, evidence: "vi.spyOn spy evidence was detected." },
    { signal: "fake-timers", pattern: /useFakeTimers|setSystemTime|advanceTimers/i, evidence: "fake timer evidence was detected." },
    { signal: "mock-reset", pattern: /clearAllMocks|resetAllMocks|restoreAllMocks|mockReset|mockRestore|afterEach/i, evidence: "mock reset or cleanup evidence was detected." },
    { signal: "fixture-data", pattern: /(^|\/)(fixtures?|__fixtures__)\//i, evidence: "fixture path evidence was detected." },
    { signal: "module-mock", pattern: /__mocks__|mockImplementation|mockResolvedValue|mockRejectedValue/i, evidence: "module mock behavior evidence was detected." },
    { signal: "request-mock", pattern: /msw|Mock Service Worker|fetchMock|nock|mock.*request|request.*mock/i, evidence: "request mocking evidence was detected." }
  ];
  return unitTestSignalFromSpecs(sourceFiles, specs, "mock", "signal");
}

function unitTestCoverageSignals(sourceFiles: UnitTestSourceFile[]): UnitTestReport["coverageSignals"] {
  const specs: Array<{ signal: UnitTestReport["coverageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "coverage-enabled", pattern: /--coverage|coverage\s*:\s*\{[\s\S]{0,300}enabled\s*:\s*true/i, evidence: "coverage enablement evidence was detected." },
    { signal: "coverage-provider-v8", pattern: /@vitest\/coverage-v8|provider\s*:\s*["']v8["']/i, evidence: "v8 coverage provider evidence was detected." },
    { signal: "coverage-provider-istanbul", pattern: /@vitest\/coverage-istanbul|provider\s*:\s*["']istanbul["']/i, evidence: "istanbul coverage provider evidence was detected." },
    { signal: "coverage-include", pattern: /coverage\s*:\s*\{[\s\S]{0,600}include\s*:/i, evidence: "coverage include pattern evidence was detected." },
    { signal: "coverage-exclude", pattern: /coverage\s*:\s*\{[\s\S]{0,600}exclude\s*:/i, evidence: "coverage exclude pattern evidence was detected." },
    { signal: "coverage-thresholds", pattern: /thresholds\s*:\s*\{|lines\s*:\s*\d+|branches\s*:\s*\d+|functions\s*:\s*\d+/i, evidence: "coverage threshold evidence was detected." },
    { signal: "coverage-reporters", pattern: /reporter(s)?\s*:\s*\[?[^\n\]]*(text|json|html|lcov|cobertura)/i, evidence: "coverage reporter evidence was detected." },
    { signal: "coverage-script", pattern: /"[^"]*coverage[^"]*"\s*:\s*"[^"]*vitest[^"]*--coverage/i, evidence: "package coverage script evidence was detected." }
  ];
  return unitTestSignalFromSpecs(sourceFiles, specs, "coverage", "signal");
}

function unitTestEnvironmentSignals(sourceFiles: UnitTestSourceFile[]): UnitTestReport["environmentSignals"] {
  const specs: Array<{ signal: UnitTestReport["environmentSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "node", pattern: /environment\s*:\s*["']node["']|node:test|process\.env/i, evidence: "Node environment evidence was detected." },
    { signal: "jsdom", pattern: /environment\s*:\s*["']jsdom["']|@vitest-environment\s+jsdom|jsdom/i, evidence: "jsdom environment evidence was detected." },
    { signal: "happy-dom", pattern: /environment\s*:\s*["']happy-dom["']|@vitest-environment\s+happy-dom|happy-dom/i, evidence: "happy-dom environment evidence was detected." },
    { signal: "browser-mode", pattern: /browser\s*:\s*\{|browser\.enabled|@vitest\/browser|playwright/i, evidence: "browser mode evidence was detected." },
    { signal: "globals", pattern: /globals\s*:\s*true/i, evidence: "globals option evidence was detected." },
    { signal: "setup-files", pattern: /setupFiles\s*:/i, evidence: "setupFiles evidence was detected." },
    { signal: "pool", pattern: /pool\s*:\s*["'](threads|forks|vmThreads|vmForks)["']/i, evidence: "pool selection evidence was detected." },
    { signal: "isolate", pattern: /isolate\s*:\s*(true|false)/i, evidence: "isolate option evidence was detected." },
    { signal: "projects", pattern: /projects\s*:\s*\[|test\.projects|defineProject/i, evidence: "project configuration evidence was detected." },
    { signal: "workspace", pattern: /vitest\.workspace|workspace\s*:/i, evidence: "workspace evidence was detected." },
    { signal: "typecheck", pattern: /typecheck\s*:\s*\{|--typecheck|expectTypeOf|assertType/i, evidence: "typecheck test evidence was detected." }
  ];
  return unitTestSignalFromSpecs(sourceFiles, specs, "environment", "signal");
}

function unitTestReportingSignals(sourceFiles: UnitTestSourceFile[]): UnitTestReport["reportingSignals"] {
  const specs: Array<{ signal: UnitTestReport["reportingSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "watch", pattern: /vitest\s+(--watch|watch)|watch\s*:\s*true/i, evidence: "watch mode evidence was detected." },
    { signal: "run", pattern: /vitest\s+run|CI\s*=\s*true/i, evidence: "run mode evidence was detected." },
    { signal: "ui", pattern: /@vitest\/ui|vitest\s+--ui|\bui\s*:\s*true/i, evidence: "Vitest UI evidence was detected." },
    { signal: "reporter", pattern: /reporter(s)?\s*:/i, evidence: "reporter config evidence was detected." },
    { signal: "junit", pattern: /junit/i, evidence: "JUnit reporter evidence was detected." },
    { signal: "json", pattern: /json\s*(?:reporter|output|summary)|reporter(s)?\s*:\s*\[?[^\n\]]*json/i, evidence: "JSON reporter evidence was detected." },
    { signal: "html", pattern: /html\s*(?:reporter|output)|reporter(s)?\s*:\s*\[?[^\n\]]*html/i, evidence: "HTML reporter evidence was detected." },
    { signal: "snapshot-update", pattern: /--update|\b-u\b|toMatch(Inline)?Snapshot/i, evidence: "snapshot update or assertion evidence was detected." },
    { signal: "filtering", pattern: /--grep|--testNamePattern|\.only\s*\(|\.skip\s*\(/i, evidence: "test filtering evidence was detected." },
    { signal: "sharding", pattern: /--shard|shard\s*:/i, evidence: "test sharding evidence was detected." },
    { signal: "benchmark", pattern: /bench\s*\(|\.bench\.|vitest\s+bench|@vitest\/bench/i, evidence: "benchmark evidence was detected." }
  ];
  return unitTestSignalFromSpecs(sourceFiles, specs, "reporting", "signal");
}

function unitTestSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: UnitTestSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/unit-tests.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildMutationTestingReadinessReport(walk: WalkResult): Promise<MutationTestingReadinessReport> {
  const sourceFiles = await mutationTestingSourceFiles(walk);
  const mutationSetups = mutationTestingSetups(sourceFiles);
  const toolSignals = mutationTestingToolSignals(sourceFiles);
  const configSignals = mutationTestingConfigSignals(sourceFiles);
  const qualitySignals = mutationTestingQualitySignals(sourceFiles);
  const reporterSignals = mutationTestingReporterSignals(sourceFiles);
  const scopeSignals = mutationTestingScopeSignals(sourceFiles);
  const packageSignals = mutationTestingPackageSignals(sourceFiles);
  const hasSetup = mutationSetups.length > 0;
  const hasPackage = packageSignals.some((item) => item.readiness === "ready");
  const hasMutate = configSignals.some((item) => item.signal === "mutate-pattern" && item.readiness === "ready")
    || scopeSignals.some((item) => ["src", "lib"].includes(item.signal) && item.readiness === "ready");
  const hasRunner = configSignals.some((item) => item.signal === "test-runner" && item.readiness === "ready");
  const hasThreshold = qualitySignals.some((item) => ["thresholds", "mutation-score", "covered-score"].includes(item.signal) && item.readiness === "ready");
  const hasReporter = reporterSignals.some((item) => ["html", "json", "dashboard", "mutation-testing-report-schema", "junit"].includes(item.signal) && item.readiness === "ready");
  const hasSafety = qualitySignals.some((item) => ["survived", "timeout", "ignored", "no-coverage"].includes(item.signal) && item.readiness === "ready")
    || scopeSignals.some((item) => ["ignore-patterns", "with-uncovered"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: MutationTestingReadinessReport["riskQueue"] = [];
  if (!hasSetup) {
    riskQueue.push({
      priority: "high",
      action: "Add mutation testing configuration before claiming mutation readiness.",
      why: "Stryker and Infection both center readiness on explicit config, mutation scope, runner, reporters, and score thresholds; this scan did not find a setup.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasPackage) {
    riskQueue.push({
      priority: "medium",
      action: "Declare the mutation testing tool dependency or documented installer.",
      why: "A config file without an installed Stryker, Infection, mutmut, or PIT package makes the repeatable command unclear.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasMutate) {
    riskQueue.push({
      priority: "high",
      action: "Define the mutation scope with mutate/source patterns.",
      why: "Mutation engines need explicit source files or directories so tests are not wasted on fixtures, generated files, or test files.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasRunner) {
    riskQueue.push({
      priority: "medium",
      action: "Connect the mutation engine to the test runner.",
      why: "Mutation score is only meaningful when the engine can run the repository's real test framework for each mutant.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasThreshold) {
    riskQueue.push({
      priority: "medium",
      action: "Set mutation score thresholds before using mutation testing as a release gate.",
      why: "Thresholds such as Stryker high/low/break or Infection min-msi/min-covered-msi convert reports into enforceable quality gates.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasReporter) {
    riskQueue.push({
      priority: "low",
      action: "Add HTML or JSON mutation reports for learner review.",
      why: "Machine-readable and browsable reports show killed, survived, timeout, ignored, and no-coverage mutants without rerunning the engine.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasSafety) {
    riskQueue.push({
      priority: "low",
      action: "Document timeout, ignored mutant, or no-coverage handling.",
      why: "Mutation testing can produce slow or intentionally equivalent mutants; safety metadata helps learners separate real gaps from tool noise.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }

  return {
    summary: `Mutation testing readiness report: setups ${mutationSetups.length}개, tool signals ${toolSignals.filter((item) => item.readiness === "ready").length}개, quality signals ${qualitySignals.filter((item) => item.readiness === "ready").length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Stryker mutation testing mutate patterns mutators testRunner coverageAnalysis reporters thresholds mutationScore killed survived timeout ignored incremental dashboard HTML JSON mutation-testing-report-schema Infection MSI covered MSI with-uncovered",
    mutationSetups,
    toolSignals,
    configSignals,
    qualitySignals,
    reporterSignals,
    scopeSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx stryker run", purpose: "Run the configured JavaScript or TypeScript mutation test suite once." },
      { command: "npx stryker run --incremental", purpose: "Reuse prior Stryker results when the repository supports incremental mutation testing." },
      { command: "npx stryker run --reporters html,json,clear-text", purpose: "Emit learner-friendly and machine-readable mutation reports." },
      { command: "npx stryker run --testRunner vitest", purpose: "Force Stryker to use the Vitest runner when the config is ambiguous." },
      { command: "vendor/bin/infection --min-msi=80 --min-covered-msi=90", purpose: "Run Infection in a trusted PHP workspace with explicit MSI gates." },
      { command: "rg \"stryker|infection|mutationScore|mutate|mutators|thresholds\" .", purpose: "Audit mutation testing configuration and report evidence statically." }
    ],
    learnerNextSteps: [
      "Open the mutation config first: identify mutate/source scope, runner, mutators, coverage analysis, timeout, reporters, and score thresholds.",
      "Compare survived mutants with existing tests and write one focused test that kills a high-value survived mutant.",
      "Use HTML/JSON mutation reports to separate killed, survived, timeout, ignored, and no-coverage mutants before changing thresholds.",
      "RepoTutor records static mutation-readiness evidence only; run Stryker or Infection in a trusted workspace before treating this as quality approval."
    ]
  };
}

type MutationTestingSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function mutationTestingSourceFiles(walk: WalkResult): Promise<MutationTestingSourceFile[]> {
  const files: MutationTestingSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !mutationTestingInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    const base = path.basename(file.relPath);
    if (!mutationTestingPathSignal(file.relPath) && !mutationTestingContentSignal(text) && base !== "package.json") continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function mutationTestingInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return mutationTestingPathSignal(filePath)
    || /^(package\.json|composer\.json|stryker\.conf\.[cm]?[jt]s|stryker\.conf\.json|stryker\.config\.[cm]?[jt]s|infection\.json5?|README\.md)$/i.test(base)
    || /\.(json|md|ya?ml|xml|php|[cm]?[jt]sx?)$/i.test(base);
}

function mutationTestingPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /(^|\/)(stryker|infection|mutmut|pitest|mutation|mutations?|mutators?|mutation-reports?|reports\/mutation|reports\/stryker|\.stryker-tmp)(\/|$)/i.test(filePath)
    || /^stryker\.(conf|config)\./i.test(base)
    || /^infection\.json5?$/i.test(base)
    || /(mutation|mutator|stryker|infection|mutmut|pitest)/i.test(filePath);
}

function mutationTestingContentSignal(text: string): boolean {
  return /\b(@stryker-mutator|stryker\s+run|Stryker|infection\/infection|bin\/infection|mutation testing|mutationScore|mutation score|mutators?|mutants?|testRunner|coverageAnalysis|disableTypeChecks|min-msi|min-covered-msi|covered MSI|with-uncovered|NoCoverage|mutation-testing-report-schema|mutmut|pitest)\b/i.test(text);
}

function mutationTestingSetups(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["mutationSetups"] {
  return sourceFiles
    .filter((source) => mutationTestingPathSignal(source.filePath) || mutationTestingContentSignal(source.text))
    .slice(0, 160)
    .map((source) => {
      const configCount = countMatches(source.text, /stryker\.conf|stryker\.config|infection\.json|pitest|mutmut|mutation testing|@stryker-mutator\/core|infection\/infection/gim);
      const mutatePatternCount = countMatches(source.text, /mutate\s*:|mutate"\s*:|sourceDirs|src\/|lib\/|--with-uncovered|with-uncovered/gim);
      const mutatorCount = countMatches(source.text, /mutator|mutators|BooleanLiteral|StringLiteral|ArrayDeclaration|ReturnRemoval/gim);
      const runnerCount = countMatches(source.text, /testRunner|vitest|jest|mocha|jasmine|phpunit|testFramework|JUnit/gim);
      const thresholdCount = countMatches(source.text, /threshold|thresholds|min-msi|min-covered-msi|mutationScore|mutation score|msi|covered MSI|high|low|break/gim);
      const reporterCount = countMatches(source.text, /reporters?|html|json|clear-text|dashboard|badge|junit|mutation-testing-report-schema|logs/gim);
      const timeoutCount = countMatches(source.text, /timeout|timeoutMS|timeoutFactor/gim);
      const incrementalCount = countMatches(source.text, /incremental|stryker-incremental|download-incremental-reports/gim);
      const ciCount = countMatches(source.text, /\.github\/workflows|CI|pull_request|workflow|dashboard/gim) + (/\.github\/workflows/i.test(source.filePath) ? 1 : 0);
      const total = configCount + mutatePatternCount + mutatorCount + runnerCount + thresholdCount + reporterCount + timeoutCount + incrementalCount + ciCount;
      return {
        filePath: source.filePath,
        tool: mutationTestingTool(source),
        configCount,
        mutatePatternCount,
        mutatorCount,
        runnerCount,
        thresholdCount,
        reporterCount,
        timeoutCount,
        incrementalCount,
        ciCount,
        readiness: configCount > 0 && mutatePatternCount > 0 && runnerCount > 0 && (thresholdCount > 0 || reporterCount > 0) && total >= 8 ? "ready" : total > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${total} mutation testing setup signal(s): scope ${mutatePatternCount}, runner ${runnerCount}, thresholds ${thresholdCount}, reporters ${reporterCount}.`,
        sourceHref: source.sourceHref
      };
    });
}

function mutationTestingTool(source: MutationTestingSourceFile): MutationTestingReadinessReport["mutationSetups"][number]["tool"] {
  if (/@stryker-mutator|stryker\s+run|stryker\.conf|Stryker/i.test(source.text) || /stryker/i.test(source.filePath)) return "stryker";
  if (/infection\/infection|bin\/infection|infection\.json|MSI|covered MSI|min-msi|min-covered-msi/i.test(source.text) || /infection/i.test(source.filePath)) return "infection";
  if (/mutation-testing-report-schema|mutation-testing-elements|mutation testing report/i.test(source.text) || /mutation-testing-elements/i.test(source.filePath)) return "mutation-testing-elements";
  if (/mutmut/i.test(source.text) || /mutmut/i.test(source.filePath)) return "mutmut";
  if (/pitest|\bPIT\b/i.test(source.text) || /pitest/i.test(source.filePath)) return "pitest";
  if (/mutation testing|mutator|mutants?/i.test(source.text) || /mutation|mutator/i.test(source.filePath)) return "custom";
  return "unknown";
}

function mutationTestingToolSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["toolSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["toolSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "stryker", pattern: /@stryker-mutator|stryker\s+run|stryker\.conf|Stryker/i, evidence: "Stryker mutation testing evidence was detected." },
    { signal: "infection", pattern: /infection\/infection|bin\/infection|infection\.json|min-msi|min-covered-msi|\bMSI\b|covered MSI/i, evidence: "Infection mutation testing evidence was detected." },
    { signal: "mutmut", pattern: /\bmutmut\b/i, evidence: "mutmut evidence was detected." },
    { signal: "pitest", pattern: /\bpitest\b|\bPIT\b/i, evidence: "PIT mutation testing evidence was detected." },
    { signal: "mutation-testing-elements", pattern: /mutation-testing-report-schema|mutation-testing-elements|mutation testing report/i, evidence: "Mutation Testing Elements report schema evidence was detected." },
    { signal: "custom", pattern: /mutation testing|mutator|mutants?|mutationScore|mutation score/i, evidence: "custom mutation testing terminology was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "tool");
}

function mutationTestingConfigSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["configSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["configSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "config-file", pattern: /stryker\.(conf|config)\.|infection\.json|pitest|mutmut/i, evidence: "mutation testing config file evidence was detected." },
    { signal: "package-script", pattern: /"[^"]*(mutation|stryker|infection)[^"]*"\s*:\s*"[^"]*(stryker|infection|mutmut|pitest)[^"]*"/i, evidence: "package script evidence was detected." },
    { signal: "schema", pattern: /\$schema|mutation-testing-report-schema|schemaVersion/i, evidence: "schema evidence was detected." },
    { signal: "mutate-pattern", pattern: /mutate\s*:|mutate"\s*:|sourceDirs|src\/|lib\/|include\s*:|files\s*:/i, evidence: "mutation scope pattern evidence was detected." },
    { signal: "test-runner", pattern: /testRunner|vitest|jest|mocha|jasmine|phpunit|testFramework/i, evidence: "test runner evidence was detected." },
    { signal: "coverage-analysis", pattern: /coverageAnalysis|perTest|all|coverage/i, evidence: "coverage analysis evidence was detected." },
    { signal: "disable-type-checks", pattern: /disableTypeChecks|disable type checks/i, evidence: "disableTypeChecks evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "config");
}

function mutationTestingQualitySignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["qualitySignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["qualitySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "thresholds", pattern: /threshold|thresholds|min-msi|min-covered-msi|high\s*:|low\s*:|break\s*:/i, evidence: "mutation threshold evidence was detected." },
    { signal: "mutation-score", pattern: /mutationScore|mutation score|\bMSI\b|min-msi/i, evidence: "mutation score evidence was detected." },
    { signal: "covered-score", pattern: /coveredScore|covered score|covered MSI|min-covered-msi/i, evidence: "covered mutation score evidence was detected." },
    { signal: "survived", pattern: /survived|Survived/i, evidence: "survived mutant evidence was detected." },
    { signal: "killed", pattern: /killed|Killed/i, evidence: "killed mutant evidence was detected." },
    { signal: "timeout", pattern: /timeout|Timeout|timeoutMS|timeoutFactor/i, evidence: "timeout mutant or config evidence was detected." },
    { signal: "ignored", pattern: /ignored|Ignored|ignoreStatic|ignore-pattern/i, evidence: "ignored mutant evidence was detected." },
    { signal: "no-coverage", pattern: /NoCoverage|no coverage|no-coverage/i, evidence: "no-coverage mutant evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "quality");
}

function mutationTestingReporterSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["reporterSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["reporterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "html", pattern: /reporters?[\s\S]{0,200}html|\bhtml\b/i, evidence: "HTML reporter evidence was detected." },
    { signal: "json", pattern: /reporters?[\s\S]{0,200}json|\bjson\b/i, evidence: "JSON reporter evidence was detected." },
    { signal: "clear-text", pattern: /clear-text|clearText/i, evidence: "clear-text reporter evidence was detected." },
    { signal: "progress", pattern: /\bprogress\b/i, evidence: "progress reporter evidence was detected." },
    { signal: "dashboard", pattern: /dashboard/i, evidence: "dashboard reporter evidence was detected." },
    { signal: "badge", pattern: /\bbadge\b/i, evidence: "badge reporter evidence was detected." },
    { signal: "junit", pattern: /\bjunit\b|JUnit/i, evidence: "JUnit reporter evidence was detected." },
    { signal: "mutation-testing-report-schema", pattern: /mutation-testing-report-schema|schemaVersion/i, evidence: "mutation testing report schema evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "reporter");
}

function mutationTestingScopeSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["scopeSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["scopeSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "src", pattern: /src\/|sourceDirs[\s\S]{0,120}src|["']src["']/i, evidence: "src mutation scope evidence was detected." },
    { signal: "lib", pattern: /lib\/|["']lib["']|mutate[\s\S]{0,120}lib/i, evidence: "lib mutation scope evidence was detected." },
    { signal: "test-files", pattern: /tests?\/|__tests__|\.test\.|\.spec\.|testRunner|phpunit/i, evidence: "test file or runner scope evidence was detected." },
    { signal: "ignore-patterns", pattern: /ignoreStatic|ignorePatterns|ignore-pattern|excludedMutations|exclude\s*:/i, evidence: "ignore pattern evidence was detected." },
    { signal: "with-uncovered", pattern: /--with-uncovered|with-uncovered|withUncovered/i, evidence: "with-uncovered evidence was detected." },
    { signal: "incremental", pattern: /incremental|stryker-incremental|download-incremental-reports/i, evidence: "incremental mutation testing evidence was detected." },
    { signal: "dry-run", pattern: /dryRun|dry-run|dry run/i, evidence: "dry-run evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "scope");
}

function mutationTestingPackageSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["packageSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "@stryker-mutator/core", pattern: /@stryker-mutator\/core/i, evidence: "@stryker-mutator/core dependency evidence was detected." },
    { signal: "@stryker-mutator/vitest-runner", pattern: /@stryker-mutator\/vitest-runner/i, evidence: "Stryker Vitest runner dependency evidence was detected." },
    { signal: "@stryker-mutator/jest-runner", pattern: /@stryker-mutator\/jest-runner/i, evidence: "Stryker Jest runner dependency evidence was detected." },
    { signal: "mutation-testing-report-schema", pattern: /mutation-testing-report-schema/i, evidence: "mutation testing report schema package evidence was detected." },
    { signal: "infection/infection", pattern: /infection\/infection|bin\/infection/i, evidence: "Infection package evidence was detected." },
    { signal: "mutmut", pattern: /\bmutmut\b/i, evidence: "mutmut package evidence was detected." },
    { signal: "pitest", pattern: /\bpitest\b|\bPIT\b/i, evidence: "PIT package evidence was detected." },
    { signal: "custom", pattern: /mutation testing|mutator|mutants?|mutationScore|mutation score/i, evidence: "custom mutation testing package or terminology evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "package");
}

function mutationTestingSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: MutationTestingSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/mutation-testing-readiness.html"
    };
  });
}

async function buildTypecheckReadinessReport(walk: WalkResult): Promise<TypecheckReadinessReport> {
  const sourceFiles = await typecheckSourceFiles(walk);
  const tsconfigFiles = typecheckTsconfigFiles(sourceFiles);
  const compilerOptionSignals = typecheckCompilerOptionSignals(sourceFiles);
  const projectSignals = typecheckProjectSignals(sourceFiles);
  const moduleResolutionSignals = typecheckModuleResolutionSignals(sourceFiles);
  const declarationSignals = typecheckDeclarationSignals(sourceFiles);
  const scriptSignals = typecheckScriptSignals(sourceFiles);
  const hasTsconfig = tsconfigFiles.length > 0;
  const hasStrict = compilerOptionSignals.some((item) => item.signal === "strict" && item.readiness === "ready");
  const hasTypecheckCommand = scriptSignals.some((item) => ["typecheck-script", "tsc", "noEmit-command", "project-build"].includes(item.signal) && item.readiness === "ready");
  const usesProjectReferences = projectSignals.some((item) => item.signal === "references" && item.readiness === "ready");
  const hasComposite = projectSignals.some((item) => item.signal === "composite" && item.readiness === "ready");
  const hasIncremental = projectSignals.some((item) => item.signal === "incremental" && item.readiness === "ready");
  const hasModuleResolution = moduleResolutionSignals.some((item) => item.signal === "moduleResolution" && item.readiness === "ready");
  const hasPaths = moduleResolutionSignals.some((item) => ["paths", "baseUrl"].includes(item.signal) && item.readiness === "ready");
  const hasDeclaration = declarationSignals.some((item) => ["declaration", "emitDeclarationOnly"].includes(item.signal) && item.readiness === "ready");
  const hasNoEmitOnError = compilerOptionSignals.some((item) => item.signal === "noEmitOnError" && item.readiness === "ready");
  const hasSkipLibCheck = compilerOptionSignals.some((item) => item.signal === "skipLibCheck" && item.readiness === "ready");

  const riskQueue: TypecheckReadinessReport["riskQueue"] = [];
  if (!hasTsconfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a tsconfig.json or jsconfig.json before claiming TypeScript typecheck readiness.",
      why: "TypeScript's project mode centers on compilerOptions, files/include/exclude, and references loaded from config files.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (!hasTypecheckCommand) {
    riskQueue.push({
      priority: "high",
      action: "Add a package script or documented command that runs tsc.",
      why: "A static tsconfig is not enough; the repository needs a repeatable typecheck command such as tsc --noEmit or tsc --build.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasTsconfig && !hasStrict) {
    riskQueue.push({
      priority: "medium",
      action: "Enable strict or document why strict type checking is intentionally disabled.",
      why: "TypeScript treats strict as the umbrella for strictNullChecks, noImplicitAny, noImplicitThis, and related strict flags.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (usesProjectReferences && !hasComposite) {
    riskQueue.push({
      priority: "high",
      action: "Pair project references with composite projects.",
      why: "TypeScript's compiler options describe composite as the constraint that allows a project to participate in project references.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (usesProjectReferences && !hasIncremental) {
    riskQueue.push({
      priority: "low",
      action: "Review incremental build info settings for referenced projects.",
      why: "TypeScript supports incremental and tsBuildInfoFile to persist project build state across runs.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasPaths && !hasModuleResolution) {
    riskQueue.push({
      priority: "medium",
      action: "Make moduleResolution explicit when using paths or baseUrl.",
      why: "TypeScript's moduleResolution strategy controls how non-relative imports and path aliases are resolved.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasDeclaration && !hasNoEmitOnError) {
    riskQueue.push({
      priority: "low",
      action: "Consider noEmitOnError for declaration-producing packages.",
      why: "Declaration outputs can become misleading if emitted while type checking errors are present.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasSkipLibCheck) {
    riskQueue.push({
      priority: "low",
      action: "Review skipLibCheck as a tradeoff, not as proof that dependency types are healthy.",
      why: "TypeScript describes skipLibCheck as skipping type checking for declaration files, which can hide third-party type conflicts.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasTypecheckCommand ? "Run the typecheck command before treating this static report as approval." : "If this repository later adds a tsc command, rerun RepoTutor to populate typecheck readiness.",
    why: "RepoTutor records static TypeScript readiness only; it does not execute tsc, resolve modules, emit declarations, or inspect real diagnostics.",
    relatedHref: "html/typecheck-readiness.html"
  });

  return {
    summary: `TypeScript typecheck readiness report: tsconfig files ${tsconfigFiles.length}개, compiler option signals ${compilerOptionSignals.length}개, project signals ${projectSignals.length}개, script signals ${scriptSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "TypeScript compilerOptions strict noImplicitAny strictNullChecks composite references declaration noEmit moduleResolution paths types skipLibCheck tsc build",
    tsconfigFiles,
    compilerOptionSignals,
    projectSignals,
    moduleResolutionSignals,
    declarationSignals,
    scriptSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx tsc --noEmit", purpose: "Run a no-output semantic typecheck for the current project." },
      { command: "npx tsc --build", purpose: "Build project references using TypeScript project mode." },
      { command: "npx tsc --showConfig", purpose: "Inspect the final compilerOptions after extends resolution." },
      { command: "npx tsc --watch --noEmit", purpose: "Keep type diagnostics running during local development." },
      { command: "npx tsc --extendedDiagnostics --noEmit", purpose: "Review typecheck performance and file counts." },
      { command: "npx tsc --traceResolution --noEmit", purpose: "Debug moduleResolution, paths, typeRoots, and types lookup behavior." }
    ],
    learnerNextSteps: [
      "Start with tsconfig files: read compilerOptions, extends, include/files/exclude, and references before looking at source code.",
      "Separate strictness flags from project build flags and declaration emit flags; they answer different readiness questions.",
      "Use --showConfig when extends or base configs are involved, then run --noEmit or --build to confirm real diagnostics.",
      "RepoTutor does not execute tsc or resolve imports; treat this report as a static checklist, not typecheck approval."
    ]
  };
}

type TypecheckSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function typecheckSourceFiles(walk: WalkResult): Promise<TypecheckSourceFile[]> {
  const files: TypecheckSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !typecheckInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!typecheckPathSignal(file.relPath) && !typecheckContentSignal(text) && path.basename(file.relPath) !== "package.json") continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function typecheckInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^tsconfig.*\.json$/i.test(base)
    || /^jsconfig.*\.json$/i.test(base)
    || /^(package\.json|pnpm-workspace\.yaml|README\.md)$/i.test(base)
    || /(typescript|typecheck|tsc|tsconfig|declaration|types|compilerOptions)/i.test(filePath)
    || /\.(json|md|ya?ml|[cm]?[jt]sx?)$/i.test(filePath);
}

function typecheckPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^tsconfig.*\.json$/i.test(base)
    || /^jsconfig.*\.json$/i.test(base)
    || /(typescript|typecheck|tsc|tsconfig|declaration|types|compilerOptions)/i.test(filePath);
}

function typecheckContentSignal(text: string): boolean {
  return /typescript|tsc\b|tsconfig|compilerOptions|strictNullChecks|noImplicitAny|noEmit|declaration|composite|references|moduleResolution|skipLibCheck|typecheck/i.test(text);
}

function typecheckTsconfigFiles(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["tsconfigFiles"] {
  return sourceFiles
    .filter((source) => /^tsconfig.*\.json$/i.test(path.basename(source.filePath)) || /^jsconfig.*\.json$/i.test(path.basename(source.filePath)))
    .slice(0, 120)
    .map((source) => {
      const compilerOptionsCount = typecheckOptionCount(source.text);
      const referencesCount = countMatches(source.text, /"references"\s*:\s*\[[\s\S]*?\]/g) > 0 ? countMatches(source.text, /"path"\s*:/g) : 0;
      const includeCount = countMatches(source.text, /"(include|files)"\s*:\s*\[[\s\S]*?\]/g);
      return {
        filePath: source.filePath,
        compilerOptionsCount,
        referencesCount,
        includeCount,
        readiness: compilerOptionsCount > 0 ? "ready" : referencesCount > 0 || includeCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${compilerOptionsCount} recognized compiler option signal(s), ${referencesCount} reference path(s), and ${includeCount} include/files list signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function typecheckOptionCount(text: string): number {
  const options = ["strict", "noImplicitAny", "strictNullChecks", "noUncheckedIndexedAccess", "exactOptionalPropertyTypes", "noEmit", "noEmitOnError", "skipLibCheck", "isolatedModules", "moduleDetection", "jsx", "target", "module", "moduleResolution", "baseUrl", "paths", "typeRoots", "types", "lib", "declaration", "declarationMap", "emitDeclarationOnly", "declarationDir", "sourceMap", "composite", "incremental", "tsBuildInfoFile"];
  return options.filter((option) => new RegExp(`"${option}"\\s*:`, "i").test(text)).length;
}

function typecheckCompilerOptionSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["compilerOptionSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["compilerOptionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "strict", pattern: /"strict"\s*:\s*true/i, evidence: "strict compiler option evidence was detected." },
    { signal: "noImplicitAny", pattern: /"noImplicitAny"\s*:\s*true/i, evidence: "noImplicitAny evidence was detected." },
    { signal: "strictNullChecks", pattern: /"strictNullChecks"\s*:\s*true/i, evidence: "strictNullChecks evidence was detected." },
    { signal: "noUncheckedIndexedAccess", pattern: /"noUncheckedIndexedAccess"\s*:\s*true/i, evidence: "noUncheckedIndexedAccess evidence was detected." },
    { signal: "exactOptionalPropertyTypes", pattern: /"exactOptionalPropertyTypes"\s*:\s*true/i, evidence: "exactOptionalPropertyTypes evidence was detected." },
    { signal: "noEmit", pattern: /"noEmit"\s*:\s*true|tsc[^"\n]*--noEmit/i, evidence: "noEmit evidence was detected." },
    { signal: "noEmitOnError", pattern: /"noEmitOnError"\s*:\s*true/i, evidence: "noEmitOnError evidence was detected." },
    { signal: "skipLibCheck", pattern: /"skipLibCheck"\s*:\s*true/i, evidence: "skipLibCheck evidence was detected." },
    { signal: "isolatedModules", pattern: /"isolatedModules"\s*:\s*true/i, evidence: "isolatedModules evidence was detected." },
    { signal: "moduleDetection", pattern: /"moduleDetection"\s*:/i, evidence: "moduleDetection evidence was detected." },
    { signal: "jsx", pattern: /"jsx"\s*:/i, evidence: "jsx compiler option evidence was detected." },
    { signal: "target", pattern: /"target"\s*:/i, evidence: "target compiler option evidence was detected." },
    { signal: "module", pattern: /"module"\s*:/i, evidence: "module compiler option evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "compiler option", "signal");
}

function typecheckProjectSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["projectSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["projectSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "references", pattern: /"references"\s*:\s*\[/i, evidence: "project references evidence was detected." },
    { signal: "composite", pattern: /"composite"\s*:\s*true/i, evidence: "composite project evidence was detected." },
    { signal: "incremental", pattern: /"incremental"\s*:\s*true/i, evidence: "incremental build evidence was detected." },
    { signal: "tsBuildInfoFile", pattern: /"tsBuildInfoFile"\s*:/i, evidence: "tsBuildInfoFile evidence was detected." },
    { signal: "include", pattern: /"include"\s*:\s*\[/i, evidence: "include list evidence was detected." },
    { signal: "exclude", pattern: /"exclude"\s*:\s*\[/i, evidence: "exclude list evidence was detected." },
    { signal: "files", pattern: /"files"\s*:\s*\[/i, evidence: "files list evidence was detected." },
    { signal: "rootDir", pattern: /"rootDir"\s*:/i, evidence: "rootDir evidence was detected." },
    { signal: "outDir", pattern: /"outDir"\s*:/i, evidence: "outDir evidence was detected." },
    { signal: "extends", pattern: /"extends"\s*:/i, evidence: "extends base config evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "project", "signal");
}

function typecheckModuleResolutionSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["moduleResolutionSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["moduleResolutionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "moduleResolution", pattern: /"moduleResolution"\s*:/i, evidence: "moduleResolution evidence was detected." },
    { signal: "baseUrl", pattern: /"baseUrl"\s*:/i, evidence: "baseUrl evidence was detected." },
    { signal: "paths", pattern: /"paths"\s*:\s*\{/i, evidence: "paths mapping evidence was detected." },
    { signal: "typeRoots", pattern: /"typeRoots"\s*:\s*\[/i, evidence: "typeRoots evidence was detected." },
    { signal: "types", pattern: /"types"\s*:\s*\[/i, evidence: "types package allowlist evidence was detected." },
    { signal: "lib", pattern: /"lib"\s*:\s*\[/i, evidence: "lib declaration bundle evidence was detected." },
    { signal: "allowImportingTsExtensions", pattern: /"allowImportingTsExtensions"\s*:\s*true/i, evidence: "allowImportingTsExtensions evidence was detected." },
    { signal: "rewriteRelativeImportExtensions", pattern: /"rewriteRelativeImportExtensions"\s*:\s*true/i, evidence: "rewriteRelativeImportExtensions evidence was detected." },
    { signal: "esModuleInterop", pattern: /"esModuleInterop"\s*:\s*true/i, evidence: "esModuleInterop evidence was detected." },
    { signal: "resolveJsonModule", pattern: /"resolveJsonModule"\s*:\s*true/i, evidence: "resolveJsonModule evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "module resolution", "signal");
}

function typecheckDeclarationSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["declarationSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["declarationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "declaration", pattern: /"declaration"\s*:\s*true/i, evidence: "declaration emit evidence was detected." },
    { signal: "declarationMap", pattern: /"declarationMap"\s*:\s*true/i, evidence: "declarationMap evidence was detected." },
    { signal: "emitDeclarationOnly", pattern: /"emitDeclarationOnly"\s*:\s*true/i, evidence: "emitDeclarationOnly evidence was detected." },
    { signal: "declarationDir", pattern: /"declarationDir"\s*:/i, evidence: "declarationDir evidence was detected." },
    { signal: "sourceMap", pattern: /"sourceMap"\s*:\s*true/i, evidence: "sourceMap evidence was detected." },
    { signal: "noEmit", pattern: /"noEmit"\s*:\s*true|tsc[^"\n]*--noEmit/i, evidence: "noEmit evidence was detected." },
    { signal: "composite-declaration", pattern: /"composite"\s*:\s*true[\s\S]{0,500}"declaration"\s*:\s*true|"declaration"\s*:\s*true[\s\S]{0,500}"composite"\s*:\s*true/i, evidence: "composite plus declaration evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "declaration", "signal");
}

function typecheckScriptSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["scriptSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "tsc", pattern: /"[^"]*"\s*:\s*"[^"]*\btsc\b[^"]*"|\btsc\b/i, evidence: "tsc command evidence was detected." },
    { signal: "typecheck-script", pattern: /"type(check|s)?"\s*:\s*"[^"]*\b(tsc|vue-tsc|svelte-check)\b/i, evidence: "typecheck script evidence was detected." },
    { signal: "build-script", pattern: /"build"\s*:\s*"[^"]*\b(tsc|tsc\s+-b|tsc\s+--build)\b/i, evidence: "build script typecheck evidence was detected." },
    { signal: "noEmit-command", pattern: /\btsc\b[^"\n]*--noEmit/i, evidence: "noEmit command evidence was detected." },
    { signal: "project-build", pattern: /\btsc\b[^"\n]*(--build|-b)\b/i, evidence: "project build command evidence was detected." },
    { signal: "watch", pattern: /\btsc\b[^"\n]*(--watch|-w)\b/i, evidence: "watch command evidence was detected." },
    { signal: "generated-types", pattern: /"types"\s*:|\.d\.ts|declaration/i, evidence: "generated type output evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function typecheckSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: TypecheckSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/typecheck-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildPackageManagerReport(walk: WalkResult): Promise<PackageManagerReport> {
  const sourceFiles = await packageManagerSourceFiles(walk);
  const manifestFiles = packageManagerManifestFiles(sourceFiles);
  const workspaceSignals = packageManagerWorkspaceSignals(sourceFiles);
  const lockfileSignals = packageManagerLockfileSignals(sourceFiles);
  const scriptSignals = packageManagerScriptSignals(sourceFiles);
  const policySignals = packageManagerPolicySignals(sourceFiles);

  const hasManifest = manifestFiles.length > 0;
  const hasPackageManagerField = policySignals.some((item) => item.signal === "packageManager" && item.readiness === "ready");
  const hasLockfile = lockfileSignals.length > 0;
  const hasWorkspaceFile = workspaceSignals.some((item) => item.signal === "workspace-file" && item.readiness === "ready");
  const hasWorkspacePackages = workspaceSignals.some((item) => item.signal === "packages-include" && item.readiness === "ready");
  const hasFrozenLockfile = scriptSignals.some((item) => item.signal === "frozen-lockfile" && item.readiness === "ready");
  const hasBuildPolicy = policySignals.some((item) => ["onlyBuiltDependencies", "allowBuilds"].includes(item.signal) && item.readiness === "ready");
  const hasPnpmfileHook = policySignals.some((item) => item.signal === "pnpmfile-hook" && item.readiness === "ready");
  const lockfileEcosystems = new Set(lockfileSignals.map((item) => item.ecosystem).filter((ecosystem) => ecosystem !== "unknown"));

  const riskQueue: PackageManagerReport["riskQueue"] = [];
  if (!hasManifest) {
    riskQueue.push({
      priority: "high",
      action: "Add a package manifest before claiming JavaScript package-manager readiness.",
      why: "Package managers start from manifest files such as package.json, where scripts, dependencies, and packageManager policy are declared.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasManifest && !hasPackageManagerField) {
    riskQueue.push({
      priority: "medium",
      action: "Declare the expected package manager and version in package.json.",
      why: "pnpm-style repositories use packageManager/devEngines to make install behavior repeatable across machines.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasManifest && !hasLockfile) {
    riskQueue.push({
      priority: "high",
      action: "Commit the matching package-manager lockfile.",
      why: "pnpm documents deterministic installs through pnpm-lock.yaml; npm, Yarn, and Bun have equivalent lockfiles for resolved dependency state.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (lockfileEcosystems.size > 1) {
    riskQueue.push({
      priority: "medium",
      action: "Choose one package-manager lockfile family for this repository.",
      why: "Multiple lockfile ecosystems make it unclear whether contributors should install with pnpm, npm, Yarn, or Bun.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspacePackages && !hasWorkspaceFile) {
    riskQueue.push({
      priority: "medium",
      action: "Move workspace package globs into an explicit workspace file or root workspace declaration.",
      why: "Monorepos need a readable workspace package list so beginners can see which folders are linked together.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspaceFile && !hasFrozenLockfile) {
    riskQueue.push({
      priority: "low",
      action: "Document a frozen-lockfile CI install command for workspace repos.",
      why: "Workspace lockfiles are useful only if CI refuses accidental lockfile drift during install.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspaceFile && !hasBuildPolicy) {
    riskQueue.push({
      priority: "low",
      action: "Review dependency build-script policy for packages that run install-time builds.",
      why: "pnpm workspace files can declare allowBuilds or related controls so install-time build scripts are explicit.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasPnpmfileHook) {
    riskQueue.push({
      priority: "low",
      action: "Review .pnpmfile hooks before trusting install-time dependency rewrites.",
      why: "pnpm hooks can mutate package manifests during resolution, so they deserve a separate learning and security review.",
      relatedHref: "html/package-manager.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run the real package-manager commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records package-manager readiness statically; it does not run install, resolve registry metadata, or execute lifecycle scripts.",
    relatedHref: "html/package-manager.html"
  });

  return {
    summary: `pnpm식 package-manager readiness report: manifest ${manifestFiles.length}개, workspace signal ${workspaceSignals.length}개, lockfile ${lockfileSignals.length}개, script signal ${scriptSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "pnpm packageManager devEngines workspace packages catalog lockfile importers allowBuilds auditConfig pnpmfile hooks recursive filter frozen-lockfile",
    manifestFiles,
    workspaceSignals,
    lockfileSignals,
    scriptSignals,
    policySignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "corepack enable", purpose: "Use the packageManager field to activate the expected package-manager binary." },
      { command: "pnpm install --frozen-lockfile", purpose: "Verify the lockfile is reproducible without modifying it." },
      { command: "pnpm -r build", purpose: "Run build scripts across workspace packages recursively." },
      { command: "pnpm -r test", purpose: "Run test scripts across workspace packages recursively." },
      { command: "pnpm audit", purpose: "Review advisory data for the current lockfile in a trusted workspace." },
      { command: "pnpm list -r --depth 0", purpose: "Inspect workspace package boundaries and direct dependencies." }
    ],
    learnerNextSteps: [
      "Start with package.json: identify packageManager, scripts, dependency groups, and whether the root is private.",
      "Then read the workspace file and lockfile together; workspace globs define projects, while the lockfile records resolved dependency state.",
      "Treat lifecycle hooks, .pnpmfile, and build-script allowlists as policy, not ordinary metadata.",
      "RepoTutor does not execute install commands; use this page as a static map before running package-manager commands yourself."
    ]
  };
}

type PackageManagerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function packageManagerSourceFiles(walk: WalkResult): Promise<PackageManagerSourceFile[]> {
  const files: PackageManagerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !packageManagerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 220_000);
    if (!text) continue;
    if (!packageManagerPathSignal(file.relPath) && !packageManagerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function packageManagerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|pnpm-workspace\.yaml|yarn\.lock|bun\.lockb?|bun\.lock|\.npmrc|\.yarnrc\.ya?ml|\.pnpmfile\.cjs|README\.md)$/i.test(base)
    || /(package-manager|packageManager|workspace|lockfile|pnpm|npm|yarn|bun|dependencies|devEngines)/i.test(filePath)
    || /\.(json|md|ya?ml|cjs|mjs|toml)$/i.test(filePath);
}

function packageManagerPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|pnpm-workspace\.yaml|yarn\.lock|bun\.lockb?|bun\.lock|\.npmrc|\.yarnrc\.ya?ml|\.pnpmfile\.cjs)$/i.test(base)
    || /(package-manager|packageManager|workspace|lockfile|pnpm|npm|yarn|bun|dependencies|devEngines)/i.test(filePath);
}

function packageManagerContentSignal(text: string): boolean {
  return /packageManager|devEngines|workspaces?|pnpm|npm|yarn|bun|lockfileVersion|dependencies|devDependencies|catalog:|allowBuilds|auditConfig|frozen-lockfile|\.pnpmfile|readPackage|beforePacking/i.test(text);
}

function packageManagerManifestFiles(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["manifestFiles"] {
  return sourceFiles
    .filter((source) => path.basename(source.filePath) === "package.json")
    .slice(0, 120)
    .map((source) => {
      let packageManager: string | null = null;
      let scriptCount = 0;
      let dependencyCount = 0;
      try {
        const json = JSON.parse(source.text) as {
          packageManager?: unknown;
          scripts?: Record<string, unknown>;
          dependencies?: Record<string, unknown>;
          devDependencies?: Record<string, unknown>;
          peerDependencies?: Record<string, unknown>;
          optionalDependencies?: Record<string, unknown>;
        };
        packageManager = typeof json.packageManager === "string" ? json.packageManager : null;
        scriptCount = Object.keys(json.scripts ?? {}).length;
        dependencyCount = Object.keys({
          ...(json.dependencies ?? {}),
          ...(json.devDependencies ?? {}),
          ...(json.peerDependencies ?? {}),
          ...(json.optionalDependencies ?? {})
        }).length;
      } catch {
        // Keep the manifest visible even when JSON parsing fails.
      }
      return {
        filePath: source.filePath,
        packageManager,
        scriptCount,
        dependencyCount,
        readiness: packageManager || dependencyCount > 0 || scriptCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} has packageManager ${packageManager ?? "not declared"}, ${scriptCount} script(s), and ${dependencyCount} dependency declaration(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function packageManagerWorkspaceSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["workspaceSignals"] {
  const specs: Array<{ signal: PackageManagerReport["workspaceSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "workspace-file", pattern: /pnpm-workspace\.ya?ml|workspaces?\s*:/i, evidence: "workspace file or root workspace declaration evidence was detected." },
    { signal: "packages-include", pattern: /packages\s*:\s*\n\s*-\s+|workspaces?\s*:\s*\[/i, evidence: "workspace package include glob evidence was detected." },
    { signal: "packages-exclude", pattern: /^\s*-\s*['"]?!|!\*\*\/|exclude/i, evidence: "workspace package exclude glob evidence was detected." },
    { signal: "workspace-protocol", pattern: /workspace:\*|workspace:\^|workspace:~/i, evidence: "workspace protocol dependency evidence was detected." },
    { signal: "catalog", pattern: /\bcatalogs?\s*:|catalog:/i, evidence: "catalog dependency version evidence was detected." },
    { signal: "overrides", pattern: /\boverrides\s*:|"overrides"\s*:/i, evidence: "dependency override evidence was detected." },
    { signal: "patched-dependencies", pattern: /patchedDependencies|patches?:|\.patch\b/i, evidence: "patched dependency evidence was detected." },
    { signal: "shared-workspace-lockfile", pattern: /shared-workspace-lockfile|sharedWorkspaceLockfile/i, evidence: "shared workspace lockfile policy evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "workspace", "signal");
}

function packageManagerLockfileSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["lockfileSignals"] {
  return sourceFiles
    .filter((source) => packageManagerLockfileEcosystem(source.filePath) !== null)
    .slice(0, 20)
    .map((source) => {
      const ecosystem = packageManagerLockfileEcosystem(source.filePath) ?? "unknown";
      const version = ecosystem === "npm" ? firstJsonNumber(source.text, "lockfileVersion") : firstMatch(source.text, /lockfileVersion:\s*['"]?([^'"\n]+)['"]?/i);
      const importerCount = ecosystem === "pnpm" ? packageManagerPnpmImporterCount(source.text) : packageManagerJsonObjectCount(source.text, "packages");
      const packageCount = ecosystem === "pnpm" ? packageManagerPnpmPackageCount(source.text) : packageManagerJsonObjectCount(source.text, "packages");
      return {
        filePath: source.filePath,
        ecosystem,
        version,
        importerCount,
        packageCount,
        readiness: version || packageCount > 0 || importerCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} appears to be a ${ecosystem} lockfile with version ${version ?? "unknown"}, ${importerCount} importer signal(s), and ${packageCount} package signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function packageManagerScriptSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["scriptSignals"] {
  const specs: Array<{ signal: PackageManagerReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "install", pattern: /\b(pnpm|npm|yarn|bun)\s+(install|i|ci)\b/i, evidence: "install command evidence was detected." },
    { signal: "dev", pattern: /"dev"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?dev\b/i, evidence: "dev script evidence was detected." },
    { signal: "build", pattern: /"build"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?build\b/i, evidence: "build script evidence was detected." },
    { signal: "test", pattern: /"test[^"]*"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?test\b/i, evidence: "test script evidence was detected." },
    { signal: "lint", pattern: /"lint[^"]*"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?lint\b/i, evidence: "lint script evidence was detected." },
    { signal: "typecheck", pattern: /"type(check|s)?"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?type(check|s)?\b/i, evidence: "typecheck script evidence was detected." },
    { signal: "workspace-recursive", pattern: /\b(pnpm\s+(-r|--recursive)|npm\s+.*--workspaces|yarn\s+workspaces|bun\s+.*--filter)\b/i, evidence: "workspace-recursive command evidence was detected." },
    { signal: "filter", pattern: /\b(--filter|-F=|-F\s+|--workspace|workspaces? foreach)\b/i, evidence: "workspace filter evidence was detected." },
    { signal: "frozen-lockfile", pattern: /--frozen-lockfile|npm\s+ci|yarn\s+install\s+--immutable|bun\s+install\s+--frozen-lockfile/i, evidence: "frozen lockfile install evidence was detected." },
    { signal: "prepare", pattern: /"preinstall"\s*:|"postinstall"\s*:|"prepare"\s*:/i, evidence: "lifecycle prepare/install hook evidence was detected." },
    { signal: "release", pattern: /"release"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?release\b|publish\b/i, evidence: "release or publish script evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function packageManagerPolicySignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["policySignals"] {
  const specs: Array<{ signal: PackageManagerReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "packageManager", pattern: /"packageManager"\s*:|packageManager:/i, evidence: "packageManager pin evidence was detected." },
    { signal: "devEngines", pattern: /"devEngines"\s*:|devEngines:/i, evidence: "devEngines policy evidence was detected." },
    { signal: "engines", pattern: /"engines"\s*:|engines:/i, evidence: "runtime engines policy evidence was detected." },
    { signal: "onlyBuiltDependencies", pattern: /onlyBuiltDependencies/i, evidence: "onlyBuiltDependencies policy evidence was detected." },
    { signal: "allowBuilds", pattern: /allowBuilds/i, evidence: "allowBuilds policy evidence was detected." },
    { signal: "auditConfig", pattern: /auditConfig|ignoreGhsas|audit-level/i, evidence: "audit configuration evidence was detected." },
    { signal: "minimumReleaseAge", pattern: /minimumReleaseAge|minimum-release-age/i, evidence: "minimum release age policy evidence was detected." },
    { signal: "nodeLinker", pattern: /nodeLinker|node-linker/i, evidence: "node linker policy evidence was detected." },
    { signal: "configDependencies", pattern: /configDependencies/i, evidence: "config dependency evidence was detected." },
    { signal: "pnpmfile-hook", pattern: /\.pnpmfile|readPackage|afterAllResolved|beforePacking/i, evidence: "pnpmfile hook evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function packageManagerSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: PackageManagerSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/package-manager.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildGitHooksReport(walk: WalkResult): Promise<GitHooksReport> {
  const sourceFiles = await gitHooksSourceFiles(walk);
  const hookFiles = gitHooksHookFiles(sourceFiles);
  const installSignals = gitHooksInstallSignals(sourceFiles);
  const commandSignals = gitHooksCommandSignals(sourceFiles);
  const policySignals = gitHooksPolicySignals(sourceFiles);
  const toolConfigFiles = gitHooksToolConfigFiles(sourceFiles);

  const hasHuskyDependency = gitHooksPackageHasDependency(sourceFiles, "husky");
  const hasHookFiles = hookFiles.length > 0;
  const hasInstallSignal = installSignals.some((item) => ["prepare-script", "postinstall-script", "husky-init", "core-hooks-path"].includes(item.signal) && item.readiness === "ready");
  const hasPreCommit = policySignals.some((item) => item.signal === "pre-commit" && item.readiness === "ready");
  const hasPrePush = policySignals.some((item) => item.signal === "pre-push" && item.readiness === "ready");
  const hasCommitMsg = policySignals.some((item) => item.signal === "commit-msg" && item.readiness === "ready");
  const hasBypassPolicy = policySignals.some((item) => ["skip-env", "no-verify"].includes(item.signal) && item.readiness === "ready");
  const hasLintStaged = commandSignals.some((item) => item.signal === "lint-staged" && item.readiness === "ready") || toolConfigFiles.some((item) => item.tool === "lint-staged");
  const hasDeprecatedHuskyShim = policySignals.some((item) => item.signal === "deprecated-husky-sh" && item.readiness === "ready");

  const riskQueue: GitHooksReport["riskQueue"] = [];
  if (!hasHookFiles && toolConfigFiles.length === 0 && !hasHuskyDependency) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether local Git hooks should be part of the learner-facing quality path.",
      why: "Husky-style projects make local checks visible through .husky hook files and install scripts, while this source has no hook evidence.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHuskyDependency && !hasHookFiles) {
    riskQueue.push({
      priority: "high",
      action: "Add or recover the .husky hook files that use the declared Husky dependency.",
      why: "A Husky dependency without hook files leaves contributors unable to see what will run before commit or push.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasInstallSignal) {
    riskQueue.push({
      priority: "medium",
      action: "Document how hooks are installed, such as a prepare script or core.hooksPath setup.",
      why: "Husky initializes Git through core.hooksPath; without an install signal, hooks may exist but never run for new contributors.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasPreCommit) {
    riskQueue.push({
      priority: "medium",
      action: "Add a pre-commit hook or document why commits do not run local checks.",
      why: "pre-commit is the common hook for fast local test, lint, format, or staged-file checks.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasPreCommit && !hasLintStaged) {
    riskQueue.push({
      priority: "low",
      action: "Consider a staged-file command for expensive lint or format hooks.",
      why: "Husky documentation points to lint-staged when teams need staged-file filtering instead of whole-repo commands.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasPrePush) {
    riskQueue.push({
      priority: "low",
      action: "Decide whether slower checks belong in pre-push instead of pre-commit.",
      why: "pre-push can protect shared branches without slowing every local commit.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (!hasCommitMsg) {
    riskQueue.push({
      priority: "low",
      action: "Add commit-msg policy only if the team relies on structured commit messages.",
      why: "commitlint-style commit-msg hooks make commit conventions explicit, but they are optional for many learning repos.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasBypassPolicy) {
    riskQueue.push({
      priority: "low",
      action: "Document emergency bypass behavior for hooks.",
      why: "Husky supports HUSKY=0 and Git supports --no-verify; learners should know when bypassing is allowed.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasDeprecatedHuskyShim) {
    riskQueue.push({
      priority: "medium",
      action: "Remove deprecated husky.sh shim lines from hook files.",
      why: "Husky v9 warns that old husky.sh sourcing lines are deprecated and will fail in v10.",
      relatedHref: "html/git-hooks.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run real hook commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records Git hook readiness statically; it does not run hooks, mutate Git config, or create commits.",
    relatedHref: "html/git-hooks.html"
  });

  return {
    summary: `Husky식 Git hook readiness report: hook file ${hookFiles.length}개, install signal ${installSignals.length}개, command signal ${commandSignals.length}개, tool config ${toolConfigFiles.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Husky .husky hook files prepare core.hooksPath pre-commit pre-push commit-msg HUSKY=0 no-verify lint-staged POSIX shell",
    hookFiles,
    installSignals,
    commandSignals,
    policySignals,
    toolConfigFiles,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "pnpm exec husky init", purpose: "Initialize a Husky hook directory and prepare script in a trusted JavaScript workspace." },
      { command: "pnpm run prepare", purpose: "Run the install hook that configures Git hooks for the repository." },
      { command: "git config --get core.hooksPath", purpose: "Confirm which hook directory Git will read from." },
      { command: "pnpm exec lint-staged", purpose: "Run staged-file tasks without creating a commit when lint-staged is configured." },
      { command: "pnpm exec commitlint --from HEAD~1 --to HEAD", purpose: "Check recent commit messages when commitlint policy exists." },
      { command: "HUSKY=0 git commit ...", purpose: "Understand the documented emergency bypass path; do not use it as a normal workflow." }
    ],
    learnerNextSteps: [
      "Start with .husky files: hook filenames explain when a command runs, and file contents explain what command runs.",
      "Then read package.json scripts; Husky usually installs through prepare or postinstall, and hooks often call package scripts.",
      "Separate fast pre-commit checks from slower pre-push checks so learners understand latency and safety tradeoffs.",
      "Treat HUSKY=0 and --no-verify as policy-sensitive escape hatches, not ordinary commands."
    ]
  };
}

type GitHooksSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function gitHooksSourceFiles(walk: WalkResult): Promise<GitHooksSourceFile[]> {
  const files: GitHooksSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !gitHooksInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!gitHooksPathSignal(file.relPath) && !gitHooksContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function gitHooksInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".husky/")
    || /^(\.lintstagedrc(\..+)?|lint-staged\.config\.(js|cjs|mjs|ts)|commitlint\.config\.(js|cjs|mjs|ts)|lefthook\.ya?ml|\.pre-commit-config\.ya?ml|\.simple-git-hooks\.(json|js|cjs)|package\.json|README\.md)$/i.test(base)
    || /(husky|lint-staged|commitlint|pre-commit|pre-push|commit-msg|git-hooks?|hooksPath|lefthook|simple-git-hooks)/i.test(filePath)
    || /\.(json|md|ya?ml|sh|bash|zsh|js|cjs|mjs|ts)$/i.test(filePath);
}

function gitHooksPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".husky/")
    || /^(\.lintstagedrc(\..+)?|lint-staged\.config\.(js|cjs|mjs|ts)|commitlint\.config\.(js|cjs|mjs|ts)|lefthook\.ya?ml|\.pre-commit-config\.ya?ml|\.simple-git-hooks\.(json|js|cjs)|package\.json)$/i.test(base)
    || /(husky|lint-staged|commitlint|pre-commit|pre-push|commit-msg|git-hooks?|hooksPath|lefthook|simple-git-hooks)/i.test(filePath);
}

function gitHooksContentSignal(text: string): boolean {
  return /husky|\.husky|core\.hooksPath|pre-commit|pre-push|commit-msg|prepare-commit-msg|HUSKY=0|--no-verify|lint-staged|commitlint|lefthook|pre-commit-config|simple-git-hooks|node_modules\/\.bin/i.test(text);
}

function gitHooksHookFiles(sourceFiles: GitHooksSourceFile[]): GitHooksReport["hookFiles"] {
  return sourceFiles
    .filter((source) => source.filePath.startsWith(".husky/") && !source.filePath.startsWith(".husky/_/") && !path.basename(source.filePath).includes("."))
    .slice(0, 80)
    .map((source) => {
      const commandCount = source.text.split(/\r?\n/).filter((line) => {
        const trimmed = line.trim();
        return trimmed.length > 0 && !trimmed.startsWith("#") && !trimmed.startsWith(". \"$(dirname");
      }).length;
      const hasBypassHint = /HUSKY=0|--no-verify|\b-n\b/i.test(source.text);
      const hasNodePathHint = /node_modules\/\.bin|\bPATH\b|NVM_DIR|nvm|fnm|asdf|volta|init\.sh/i.test(source.text);
      return {
        filePath: source.filePath,
        hookName: path.basename(source.filePath),
        commandCount,
        hasBypassHint,
        hasNodePathHint,
        readiness: commandCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} declares ${commandCount} executable command line(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function gitHooksInstallSignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["installSignals"] {
  const specs: Array<{ signal: GitHooksReport["installSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prepare-script", pattern: /"prepare"\s*:\s*"[^"]*husky|prepare.*husky/i, evidence: "prepare script or prepare documentation for Husky was detected." },
    { signal: "postinstall-script", pattern: /"postinstall"\s*:\s*"[^"]*husky|postinstall.*husky/i, evidence: "postinstall hook setup evidence was detected." },
    { signal: "husky-init", pattern: /\b(npx|pnpm exec|bunx|yarn dlx)?\s*husky\s+init\b/i, evidence: "husky init setup evidence was detected." },
    { signal: "core-hooks-path", pattern: /core\.hooksPath|hooksPath|git config.*core\.hooksPath|\.husky\/_/i, evidence: "Git core.hooksPath setup evidence was detected." },
    { signal: "git-root-subdir", pattern: /cd\s+\.\.\s*&&\s*husky|husky\s+[^"'\n]*\/\.husky|Project Not in Git Root Directory/i, evidence: "subdirectory project hook setup evidence was detected." },
    { signal: "ci-skip", pattern: /HUSKY=0|process\.env\.CI|CI\s*={0,2}\s*['"]?true|NODE_ENV\s*={0,2}\s*['"]?production/i, evidence: "CI or production hook install skip evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "install", "signal");
}

function gitHooksCommandSignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["commandSignals"] {
  const specs: Array<{ signal: GitHooksReport["commandSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "test", pattern: /\b(npm|pnpm|yarn|bun)\s+(run\s+)?test\b|\bvitest\b|\bjest\b/i, evidence: "test command evidence was detected." },
    { signal: "lint", pattern: /\b(npm|pnpm|yarn|bun)\s+(run\s+)?lint\b|\beslint\b|\blint\b/i, evidence: "lint command evidence was detected." },
    { signal: "format", pattern: /\bprettier\b|\bformat\b/i, evidence: "format command evidence was detected." },
    { signal: "typecheck", pattern: /\btsc\b|typecheck|type-check/i, evidence: "typecheck command evidence was detected." },
    { signal: "security", pattern: /\bgitleaks\b|\bsemgrep\b|\bsnyk\b|\baudit\b/i, evidence: "security or audit command evidence was detected." },
    { signal: "commitlint", pattern: /\bcommitlint\b|commit-msg/i, evidence: "commit message lint evidence was detected." },
    { signal: "lint-staged", pattern: /\blint-staged\b|lintstaged/i, evidence: "staged-file task evidence was detected." },
    { signal: "npm-run", pattern: /\bnpm\s+run\s+/i, evidence: "npm script invocation evidence was detected." },
    { signal: "pnpm-run", pattern: /\bpnpm\s+(run|exec)\s+/i, evidence: "pnpm script or exec invocation evidence was detected." },
    { signal: "node-entrypoint", pattern: /\bnode\s+\.husky\/[^\s]+|\bnode\s+[^"'\n]*(pre-commit|pre-push|commit-msg)[^"'\n]*\.(mjs|cjs|js)\b|\.husky\/[^\s"']+\.(mjs|cjs|js)\b/i, evidence: "Node hook entrypoint evidence was detected." },
    { signal: "posix-shell", pattern: /^#!\/(?:usr\/bin\/env\s+)?sh\b|POSIX|bash\s+<<\s*EOF|set\s+-e/im, evidence: "POSIX shell hook evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "command", "signal");
}

function gitHooksPolicySignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["policySignals"] {
  const specs: Array<{ signal: GitHooksReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "pre-commit", pattern: /\.husky\/pre-commit|\bpre-commit\b/i, evidence: "pre-commit hook evidence was detected." },
    { signal: "pre-push", pattern: /\.husky\/pre-push|\bpre-push\b/i, evidence: "pre-push hook evidence was detected." },
    { signal: "commit-msg", pattern: /\.husky\/commit-msg|\bcommit-msg\b/i, evidence: "commit-msg hook evidence was detected." },
    { signal: "prepare-commit-msg", pattern: /\.husky\/prepare-commit-msg|\bprepare-commit-msg\b/i, evidence: "prepare-commit-msg hook evidence was detected." },
    { signal: "post-merge", pattern: /\.husky\/post-merge|\bpost-merge\b/i, evidence: "post-merge hook evidence was detected." },
    { signal: "skip-env", pattern: /HUSKY=0|export\s+HUSKY=0/i, evidence: "HUSKY=0 skip policy evidence was detected." },
    { signal: "no-verify", pattern: /--no-verify|git\s+\w+[^\n]*\s-n(\s|$)/i, evidence: "Git --no-verify bypass evidence was detected." },
    { signal: "gui-node-path", pattern: /init\.sh|node_modules\/\.bin|\bPATH\b|NVM_DIR|version manager|nvm|fnm|asdf|volta/i, evidence: "GUI or Node PATH mitigation evidence was detected." },
    { signal: "deprecated-husky-sh", pattern: /husky\.sh|_\/husky\.sh/i, evidence: "deprecated husky.sh shim evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function gitHooksToolConfigFiles(sourceFiles: GitHooksSourceFile[]): GitHooksReport["toolConfigFiles"] {
  return sourceFiles
    .filter((source) => gitHooksToolForPath(source.filePath, source.text) !== null)
    .slice(0, 80)
    .map((source) => {
      const tool = gitHooksToolForPath(source.filePath, source.text) ?? "unknown";
      return {
        filePath: source.filePath,
        tool,
        readiness: tool === "unknown" ? "partial" : "ready",
        evidence: `${source.filePath} contains ${tool} hook-tool configuration evidence.`,
        sourceHref: source.sourceHref
      };
    });
}

function gitHooksToolForPath(filePath: string, text: string): GitHooksReport["toolConfigFiles"][number]["tool"] | null {
  const base = path.basename(filePath).toLowerCase();
  if (filePath.startsWith(".husky/") || /\bhusky\b/i.test(text)) return "husky";
  if (/^\.lintstagedrc|lint-staged\.config\./i.test(base) || /\blint-staged\b|lintstaged/i.test(text)) return "lint-staged";
  if (/^commitlint\.config\./i.test(base) || /\bcommitlint\b/i.test(text)) return "commitlint";
  if (/^lefthook\.ya?ml$/i.test(base) || /\blefthook\b/i.test(text)) return "lefthook";
  if (/^\.pre-commit-config\.ya?ml$/i.test(base) || /\brepos:\s*\n[\s\S]*hooks:/i.test(text)) return "pre-commit";
  if (/^\.simple-git-hooks\./i.test(base) || /simple-git-hooks/i.test(text)) return "simple-git-hooks";
  return null;
}

function gitHooksPackageHasDependency(sourceFiles: GitHooksSourceFile[], dependencyName: string): boolean {
  return sourceFiles.some((source) => {
    if (path.basename(source.filePath) !== "package.json") return false;
    try {
      const json = JSON.parse(source.text) as {
        dependencies?: Record<string, unknown>;
        devDependencies?: Record<string, unknown>;
        optionalDependencies?: Record<string, unknown>;
      };
      return Boolean(json.dependencies?.[dependencyName] ?? json.devDependencies?.[dependencyName] ?? json.optionalDependencies?.[dependencyName]);
    } catch {
      return source.text.includes(`"${dependencyName}"`);
    }
  });
}

function gitHooksSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: GitHooksSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/git-hooks.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildTaskRunnerReport(walk: WalkResult): Promise<TaskRunnerReport> {
  const sourceFiles = await taskRunnerSourceFiles(walk);
  const configFiles = taskRunnerConfigFiles(sourceFiles);
  const taskSignals = taskRunnerTaskSignals(sourceFiles);
  const cacheSignals = taskRunnerCacheSignals(sourceFiles);
  const dependencySignals = taskRunnerDependencySignals(sourceFiles);
  const environmentSignals = taskRunnerEnvironmentSignals(sourceFiles);
  const packageScriptSignals = taskRunnerPackageScriptSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasTurboScript = packageScriptSignals.some((item) => item.signal === "turbo-run" && item.readiness === "ready");
  const hasTaskDependencies = dependencySignals.some((item) => ["depends-on", "caret-dependency"].includes(item.signal) && item.readiness === "ready");
  const hasOutputs = cacheSignals.some((item) => item.signal === "outputs" && item.readiness === "ready");
  const hasInputs = cacheSignals.some((item) => item.signal === "inputs" && item.readiness === "ready");
  const hasEnv = environmentSignals.some((item) => ["globalEnv", "globalPassThroughEnv", "passThroughEnv", "env"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: TaskRunnerReport["riskQueue"] = [];
  if (!hasConfig && !hasTurboScript) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether workspace task orchestration should be documented for learners.",
      why: "Turbo-style monorepos make build/test/lint ordering and cache boundaries explicit through task-runner config and package scripts.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasTurboScript && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add the task-runner config that explains the turbo script behavior.",
      why: "A package script that calls turbo without turbo.json makes task dependencies, inputs, outputs, and cache policy hard to inspect.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasTaskDependencies) {
    riskQueue.push({
      priority: "medium",
      action: "Document task ordering with dependsOn where build/test tasks depend on upstream packages.",
      why: "Turborepo uses dependsOn such as ^build to express workspace task graph order.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasOutputs) {
    riskQueue.push({
      priority: "medium",
      action: "Declare cacheable task outputs for build-like tasks.",
      why: "Task runner caching needs output paths so learners can understand what is restored or invalidated.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasInputs) {
    riskQueue.push({
      priority: "low",
      action: "Review task inputs for expensive tasks or generated artifacts.",
      why: "Turbo-style inputs let teams narrow cache invalidation and avoid costly glob walking.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasEnv) {
    riskQueue.push({
      priority: "low",
      action: "Document environment variables that affect cached task results.",
      why: "Turbo separates env, globalEnv, and pass-through env so cache keys and runtime-only variables are explicit.",
      relatedHref: "html/task-runner.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run task-runner commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records task-runner readiness statically; it does not run builds, restore cache, or contact remote cache services.",
    relatedHref: "html/task-runner.html"
  });

  return {
    summary: `Turborepo식 task-runner readiness report: config file ${configFiles.length}개, task signal ${taskSignals.length}개, cache signal ${cacheSignals.length}개, dependency signal ${dependencySignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Turborepo turbo.json tasks dependsOn outputs inputs cache env globalEnv passThroughEnv persistent turbo run filter remote cache",
    configFiles,
    taskSignals,
    cacheSignals,
    dependencySignals,
    environmentSignals,
    packageScriptSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "pnpm turbo run build --dry=json", purpose: "Inspect the task graph and package selection without running build work." },
      { command: "pnpm turbo run test --filter <package>", purpose: "Run a scoped task for one package when the workspace is trusted." },
      { command: "pnpm turbo run build --summarize", purpose: "Review cache inputs, outputs, and task summaries after a real run." },
      { command: "pnpm turbo daemon status", purpose: "Check local Turbo daemon state when task discovery feels stale." },
      { command: "pnpm turbo prune <package>", purpose: "Understand which files a package needs for isolated builds." },
      { command: "pnpm turbo run lint --cache=local:rw", purpose: "Keep cache behavior local while validating a lint task." }
    ],
    learnerNextSteps: [
      "Start with turbo.json: task names explain what can be orchestrated, dependsOn explains ordering, and outputs explain cache artifacts.",
      "Then read package.json scripts to see which commands call the task runner and which remain direct package-manager scripts.",
      "Separate cache-key inputs from runtime-only pass-through environment variables before trusting task results.",
      "RepoTutor does not run task-runner commands; use this page as a static map before executing workspace tasks yourself."
    ]
  };
}

type TaskRunnerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function taskRunnerSourceFiles(walk: WalkResult): Promise<TaskRunnerSourceFile[]> {
  const files: TaskRunnerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !taskRunnerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!taskRunnerPathSignal(file.relPath) && !taskRunnerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function taskRunnerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json|README\.md)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|turborepo|task-runner|taskfile|moonrepo|nx|monorepo|workspace)/i.test(filePath)
    || /\.(json|md|ya?ml|toml)$/i.test(filePath);
}

function taskRunnerPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|turborepo|task-runner|taskfile|moonrepo|nx)/i.test(filePath);
}

function taskRunnerContentSignal(text: string): boolean {
  return /\bturbo\b|turborepo|\"tasks\"\s*:|\"pipeline\"\s*:|dependsOn|outputs|inputs|globalEnv|globalPassThroughEnv|passThroughEnv|remoteCache|cache\s*:\s*false|persistent|nx\s+run|moon\s+run|Taskfile/i.test(text);
}

function taskRunnerConfigFiles(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["configFiles"] {
  return sourceFiles
    .filter((source) => taskRunnerConfigPathSignal(source.filePath) && taskRunnerToolForPath(source.filePath, source.text) !== null)
    .slice(0, 80)
    .map((source) => {
      const tool = taskRunnerToolForPath(source.filePath, source.text) ?? "unknown";
      const taskCount = taskRunnerTaskCount(source.text);
      const dependsOnCount = countMatches(source.text, /dependsOn/g);
      const outputsCount = countMatches(source.text, /outputs/g);
      return {
        filePath: source.filePath,
        tool,
        taskCount,
        dependsOnCount,
        outputsCount,
        readiness: taskCount > 0 || dependsOnCount > 0 || outputsCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} contains ${tool} task-runner config with ${taskCount} task signal(s), ${dependsOnCount} dependency signal(s), and ${outputsCount} output signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function taskRunnerConfigPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|task-runner|taskfile|moonrepo|nx|lage).*\.(json|ya?ml|toml)$/i.test(filePath);
}

function taskRunnerToolForPath(filePath: string, text: string): TaskRunnerReport["configFiles"][number]["tool"] | null {
  const base = path.basename(filePath).toLowerCase();
  if (base === "turbo.json" || /\bturbo\b|turborepo/i.test(text)) return "turbo";
  if (base === "nx.json" || base === "project.json" || /\bnx\s+run|\bnx\b/i.test(text)) return "nx";
  if (/^taskfile\.ya?ml$/i.test(base)) return "taskfile";
  if (base === "moon.yml" || base === "moon.yaml" || filePath.startsWith(".moon/") || /\bmoon\s+run\b/i.test(text)) return "moon";
  if (/\blage\b/i.test(text)) return "lage";
  return null;
}

function taskRunnerTaskCount(text: string): number {
  try {
    const cleaned = stripJsonComments(text);
    const json = JSON.parse(cleaned) as { tasks?: Record<string, unknown>; pipeline?: Record<string, unknown> };
    return Object.keys(json.tasks ?? json.pipeline ?? {}).length;
  } catch {
    const section = text.match(/"?(tasks|pipeline)"?\s*:\s*\{([\s\S]*?)\n\s*\}/)?.[2] ?? "";
    return Math.max(countMatches(section, /"[^"]+"\s*:/g), 0);
  }
}

function taskRunnerTaskSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["taskSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["taskSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "build", pattern: /"build[^"]*"\s*:|\bturbo\s+run\s+build\b|\bnx\s+run\s+\S+:build\b/i, evidence: "build task evidence was detected." },
    { signal: "test", pattern: /"test[^"]*"\s*:|\bturbo\s+run\s+test\b|\bnx\s+run\s+\S+:test\b/i, evidence: "test task evidence was detected." },
    { signal: "lint", pattern: /"lint[^"]*"\s*:|\bturbo\s+run\s+lint\b|\bnx\s+run\s+\S+:lint\b/i, evidence: "lint task evidence was detected." },
    { signal: "dev", pattern: /"dev[^"]*"\s*:|\bturbo\s+run\s+dev\b/i, evidence: "dev task evidence was detected." },
    { signal: "typecheck", pattern: /typecheck|check-types|tsc\s+-b/i, evidence: "typecheck task evidence was detected." },
    { signal: "format", pattern: /"format[^"]*"\s*:|\bturbo\s+run\s+format\b|prettier|oxfmt/i, evidence: "format task evidence was detected." },
    { signal: "quality", pattern: /quality|check|verify/i, evidence: "quality or check task evidence was detected." },
    { signal: "release", pattern: /release|publish|deploy/i, evidence: "release or deploy task evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "task", "signal");
}

function taskRunnerCacheSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["cacheSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["cacheSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "outputs", pattern: /"outputs"\s*:|outputs:/i, evidence: "cache output declaration evidence was detected." },
    { signal: "inputs", pattern: /"inputs"\s*:|inputs:/i, evidence: "cache input declaration evidence was detected." },
    { signal: "cache-false", pattern: /"cache"\s*:\s*false|cache:\s*false/i, evidence: "cache disabled task evidence was detected." },
    { signal: "remote-cache", pattern: /remoteCache|remote cache|TURBO_TOKEN|TURBO_TEAM/i, evidence: "remote cache evidence was detected." },
    { signal: "global-env", pattern: /globalEnv|globalDependencies/i, evidence: "global cache environment evidence was detected." },
    { signal: "pass-through-env", pattern: /globalPassThroughEnv|passThroughEnv/i, evidence: "pass-through environment evidence was detected." },
    { signal: "persistent", pattern: /"persistent"\s*:\s*true|persistent:\s*true/i, evidence: "persistent task evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "cache", "signal");
}

function taskRunnerDependencySignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["dependencySignals"] {
  const specs: Array<{ signal: TaskRunnerReport["dependencySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "depends-on", pattern: /dependsOn/i, evidence: "task dependsOn evidence was detected." },
    { signal: "caret-dependency", pattern: /"\^[^"]+"|\^build|\^topo/i, evidence: "upstream workspace dependency task evidence was detected." },
    { signal: "root-task", pattern: /"\/\/#|\/\/#/i, evidence: "root task evidence was detected." },
    { signal: "package-task", pattern: /[A-Za-z0-9_-]+#[A-Za-z0-9:_-]+/i, evidence: "package-scoped task evidence was detected." },
    { signal: "filter", pattern: /--filter|-F\s+|--affected|affected:/i, evidence: "task filter evidence was detected." },
    { signal: "workspace-script", pattern: /workspace|workspaces|pnpm\s+-r|pnpm\s+--filter|turbo\s+run/i, evidence: "workspace script orchestration evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "dependency", "signal");
}

function taskRunnerEnvironmentSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["environmentSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["environmentSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "globalEnv", pattern: /globalEnv/i, evidence: "globalEnv evidence was detected." },
    { signal: "globalPassThroughEnv", pattern: /globalPassThroughEnv/i, evidence: "globalPassThroughEnv evidence was detected." },
    { signal: "passThroughEnv", pattern: /passThroughEnv/i, evidence: "passThroughEnv evidence was detected." },
    { signal: "env", pattern: /"env"\s*:|env:/i, evidence: "task env evidence was detected." },
    { signal: "dot-env", pattern: /\.env|dotenv/i, evidence: "dot-env file evidence was detected." },
    { signal: "ci", pattern: /RUNNER_OS|GITHUB_ACTIONS|CI\b|ACTIONS_/i, evidence: "CI environment evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "environment", "signal");
}

function taskRunnerPackageScriptSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["packageScriptSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["packageScriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "turbo-run", pattern: /\bturbo\s+run\b|\bpnpm\s+--\s+turbo\b|\bnpx\s+turbo\b/i, evidence: "turbo run package script evidence was detected." },
    { signal: "nx-run", pattern: /\bnx\s+run\b|\bnx\s+affected\b/i, evidence: "Nx run package script evidence was detected." },
    { signal: "task-run", pattern: /\btask\s+[A-Za-z0-9:_-]+|Taskfile\.ya?ml/i, evidence: "Taskfile task script evidence was detected." },
    { signal: "moon-run", pattern: /\bmoon\s+run\b/i, evidence: "Moon task script evidence was detected." },
    { signal: "recursive-run", pattern: /\bpnpm\s+-r\b|\bnpm\s+.*--workspaces\b|yarn\s+workspaces/i, evidence: "recursive workspace package script evidence was detected." },
    { signal: "filter-run", pattern: /--filter|-F\s+|--affected/i, evidence: "filtered task run evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "package script", "signal");
}

function taskRunnerSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: TaskRunnerSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/task-runner.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

function stripJsonComments(text: string): string {
  return text.replace(/\/\/.*$/gm, "").replace(/\/\*[\s\S]*?\*\//g, "");
}

async function buildDependencyUpdateReport(walk: WalkResult): Promise<DependencyUpdateReport> {
  const sourceFiles = await dependencyUpdateSourceFiles(walk);
  const configFiles = dependencyUpdateConfigFiles(sourceFiles);
  const managerSignals = dependencyUpdateManagerSignals(sourceFiles);
  const policySignals = dependencyUpdatePolicySignals(sourceFiles);
  const workflowSignals = dependencyUpdateWorkflowSignals(sourceFiles);
  const registrySignals = dependencyUpdateRegistrySignals(sourceFiles);
  const packageFileSignals = dependencyUpdatePackageFileSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasPackageFiles = packageFileSignals.some((item) => item.readiness === "ready");
  const hasPackageRules = policySignals.some((item) => item.signal === "package-rules" && item.readiness === "ready");
  const hasDashboard = policySignals.some((item) => item.signal === "dependency-dashboard" && item.readiness === "ready");
  const hasRateLimits = policySignals.some((item) => item.signal === "rate-limits" && item.readiness === "ready");
  const hasRegistryRules = registrySignals.some((item) => ["host-rules", "registry-url", "private-packages"].includes(item.signal) && item.readiness === "ready");
  const hasAutomerge = policySignals.some((item) => item.signal === "automerge" && item.readiness === "ready");
  const hasSchedule = policySignals.some((item) => item.signal === "schedule" && item.readiness === "ready");

  const riskQueue: DependencyUpdateReport["riskQueue"] = [];
  if (hasPackageFiles && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a dependency update configuration before relying on automated update PRs.",
      why: "Renovate-style automation needs repository policy for presets, grouping, schedules, and review boundaries.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasPackageRules) {
    riskQueue.push({
      priority: "medium",
      action: "Review packageRules for grouping, major-update handling, and ecosystem-specific policy.",
      why: "Renovate packageRules make selective automerge, labels, schedules, grouping, and manager-specific rules inspectable.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasDashboard) {
    riskQueue.push({
      priority: "medium",
      action: "Consider a dependency dashboard or approval workflow for high-risk updates.",
      why: "Dependency dashboards give maintainers a single queue for approvals, blocked updates, and manual decisions.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasRateLimits) {
    riskQueue.push({
      priority: "low",
      action: "Set PR or branch concurrency limits when the repository has many dependency files.",
      why: "Automated update tools can create noisy PR bursts unless concurrency and hourly limits are explicit.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasRegistryRules) {
    riskQueue.push({
      priority: "medium",
      action: "Verify private registry credentials outside static RepoTutor analysis.",
      why: "RepoTutor can detect hostRules and registry URLs, but it does not validate tokens, access, or registry reachability.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasAutomerge && !hasSchedule) {
    riskQueue.push({
      priority: "medium",
      action: "Pair automerge with schedule, status-check, and branch-protection review.",
      why: "Renovate warns that automerge behavior depends on checks, platform automerge mode, and schedule semantics.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run the config validator and dry-run in a trusted workspace before enabling update PRs.",
    why: "RepoTutor records dependency-update readiness statically; it does not query registries, create branches, or open pull requests.",
    relatedHref: "html/dependency-updates.html"
  });

  return {
    summary: `Renovate식 dependency-update readiness report: config file ${configFiles.length}개, manager signal ${managerSignals.length}개, policy signal ${policySignals.length}개, package file signal ${packageFileSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Renovate config presets packageRules automerge schedule dependencyDashboard enabledManagers hostRules rangeStrategy prConcurrentLimit configMigration",
    configFiles,
    managerSignals,
    policySignals,
    workflowSignals,
    registrySignals,
    packageFileSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx renovate-config-validator", purpose: "Validate Renovate config syntax and schema in a trusted workspace." },
      { command: "npx renovate --dry-run=full", purpose: "Preview discovered dependencies, branches, and PR decisions without writing changes." },
      { command: "npx renovate --print-config", purpose: "Inspect the resolved config after presets and inherited settings are applied." },
      { command: "npx renovate --platform=github --autodiscover=false <owner/repo>", purpose: "Run a scoped repository check instead of broad autodiscovery." },
      { command: "npx renovate --dry-run=lookup", purpose: "Check lookup behavior before creating branches or pull requests." },
      { command: "gh workflow run renovate.yml --ref <branch>", purpose: "Trigger a dedicated Renovate workflow only after reviewing workflow permissions." }
    ],
    learnerNextSteps: [
      "Start with renovate.json, .renovaterc, or dependabot.yml to find the automation policy before reading package manifests.",
      "Check packageRules and schedules before trusting automerge or grouped dependency PRs.",
      "Separate public package-file discovery from private registry credentials such as hostRules and token environment variables.",
      "RepoTutor does not call registries or create branches; use this page as a static review map before enabling automation."
    ]
  };
}

type DependencyUpdateSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function dependencyUpdateSourceFiles(walk: WalkResult): Promise<DependencyUpdateSourceFile[]> {
  const files: DependencyUpdateSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !dependencyUpdateInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!dependencyUpdatePathSignal(file.relPath) && !dependencyUpdatePackageFilePathSignal(file.relPath) && !dependencyUpdateContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function dependencyUpdateInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return dependencyUpdatePathSignal(filePath)
    || /^(package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|Dockerfile|go\.mod|pyproject\.toml|requirements.*\.txt|Gemfile|versions\.tf)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(json|json5|ya?ml|toml|md)$/i.test(filePath);
}

function dependencyUpdatePathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(renovate\.json|renovate\.json5|\.renovaterc|\.renovaterc\.json|\.renovaterc\.json5|\.renovaterc\.ya?ml|renovate\.config\.[cm]?[jt]s|dependabot\.ya?ml)$/i.test(base)
    || filePath === ".github/dependabot.yml"
    || filePath === ".github/dependabot.yaml"
    || /renovate|dependabot|dependency-update|dependency-updates/i.test(filePath);
}

function dependencyUpdatePackageFilePathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|Dockerfile|go\.mod|pyproject\.toml|requirements.*\.txt|Gemfile|versions\.tf)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.tf$/i.test(filePath);
}

function dependencyUpdateContentSignal(text: string): boolean {
  return /renovate|dependabot|packageRules|dependencyDashboard|automerge|hostRules|enabledManagers|rangeStrategy|prConcurrentLimit|branchConcurrentLimit|lockFileMaintenance/i.test(text);
}

function dependencyUpdateConfigFiles(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["configFiles"] {
  return sourceFiles
    .filter((source) => dependencyUpdateConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = dependencyUpdateConfigType(source.filePath, source.text);
      const extendsCount = countMatches(source.text, /"extends"\s*:|extends:/g);
      const packageRuleCount = dependencyUpdatePackageRuleCount(source.text);
      const scheduleCount = countMatches(source.text, /schedule|automergeSchedule/g);
      const automergeSignal = dependencyUpdateAutomergeSignal(source.text);
      return {
        filePath: source.filePath,
        configType,
        extendsCount,
        packageRuleCount,
        scheduleCount,
        automergeSignal,
        readiness: extendsCount > 0 || packageRuleCount > 0 || scheduleCount > 0 || automergeSignal !== "missing" ? "ready" : "partial",
        evidence: `${source.filePath} contains ${configType} dependency-update config with ${extendsCount} preset signal(s), ${packageRuleCount} package rule signal(s), and ${scheduleCount} schedule signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function dependencyUpdateConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return dependencyUpdatePathSignal(filePath)
    || (base === "package.json" && /"renovate"\s*:/.test(text))
    || (filePath.startsWith(".github/workflows/") && /\brenovate\b|dependabot/i.test(text));
}

function dependencyUpdateConfigType(filePath: string, text: string): DependencyUpdateReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (filePath === ".github/dependabot.yml" || filePath === ".github/dependabot.yaml" || /dependabot/i.test(filePath)) return "dependabot";
  if (base === "package.json") return "package-json";
  if (filePath.startsWith(".github/workflows/")) return "github-action";
  if (/renovate|packageRules|dependencyDashboard|hostRules|enabledManagers/i.test(filePath) || /renovate|packageRules|dependencyDashboard|hostRules|enabledManagers/i.test(text)) return "renovate";
  return "unknown";
}

function dependencyUpdatePackageRuleCount(text: string): number {
  try {
    const cleaned = stripJsonComments(text);
    const json = JSON.parse(cleaned) as { packageRules?: unknown[]; renovate?: { packageRules?: unknown[] } };
    return Array.isArray(json.packageRules) ? json.packageRules.length : Array.isArray(json.renovate?.packageRules) ? json.renovate.packageRules.length : 0;
  } catch {
    const section = text.match(/packageRules["']?\s*:\s*\[([\s\S]*?)\n\s*\]/)?.[1] ?? "";
    return Math.max(countMatches(section, /\{[\s\S]*?\}/g), countMatches(text, /packageRules/g));
  }
}

function dependencyUpdateAutomergeSignal(text: string): DependencyUpdateReport["configFiles"][number]["automergeSignal"] {
  if (/automerge[^:\n]*["']?\s*:\s*true|platformAutomerge[^:\n]*["']?\s*:\s*true/i.test(text)) return /packageRules|matchPackage|matchDep|matchUpdateTypes/i.test(text) ? "conditional" : "enabled";
  if (/automerge[^:\n]*["']?\s*:\s*false|platformAutomerge[^:\n]*["']?\s*:\s*false/i.test(text)) return "disabled";
  if (/automergeType|automergeSchedule|automergeStrategy/i.test(text)) return "conditional";
  return "missing";
}

function dependencyUpdateManagerSignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["managerSignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["managerSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "npm", pattern: /package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|npm|pnpm|yarn|bun/i, evidence: "npm-family dependency manager evidence was detected." },
    { signal: "docker", pattern: /Dockerfile|dockerfile|containerbase|docker-compose|docker/i, evidence: "Docker dependency manager evidence was detected." },
    { signal: "github-actions", pattern: /\.github\/workflows|github-actions|github action/i, evidence: "GitHub Actions dependency manager evidence was detected." },
    { signal: "python", pattern: /pyproject\.toml|requirements.*\.txt|poetry|pipenv|pip-compile/i, evidence: "Python dependency manager evidence was detected." },
    { signal: "go", pattern: /go\.mod|go\.sum|gomod|golang/i, evidence: "Go module manager evidence was detected." },
    { signal: "ruby", pattern: /Gemfile|bundler|rubygems/i, evidence: "Ruby dependency manager evidence was detected." },
    { signal: "terraform", pattern: /\.tf\b|terraform|terragrunt/i, evidence: "Terraform dependency manager evidence was detected." },
    { signal: "maven", pattern: /pom\.xml|maven/i, evidence: "Maven dependency manager evidence was detected." },
    { signal: "gradle", pattern: /build\.gradle|gradle/i, evidence: "Gradle dependency manager evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "manager", "signal");
}

